INSERT INTO nds_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 7212, 'Pokémon HeartGold Version | Pokémon SoulSilver Version', 'Nintendo DS', 18, 10107, 10107, 10107, 136, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2009-09-12', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/063592.png', 'https://media.retroachievements.org/Images/036144.png', 'https://media.retroachievements.org/Images/036139.png', 'https://media.retroachievements.org/Images/036140.png', 5),
  (2, 5522, 'Castlevania: Dawn of Sorrow', 'Nintendo DS', 18, 7727, 7727, 7727, 68, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2005-08-25', 'Castlevania: Dawn of Sorrow is a 2005 action role-playing game developed and published by Konami. It is part of Konami''s Castlevania video game series and the first Castlevania game released on the Nintendo DS. The game is the sequel to Castlevania: Aria of Sorrow and incorporates many elements from its predecessor.', 'https://media.retroachievements.org/Images/106339.png', 'https://media.retroachievements.org/Images/071783.png', 'https://media.retroachievements.org/Images/071784.png', 'https://media.retroachievements.org/Images/071785.png', 4.9),
  (3, 14806, 'Sonic Rush', 'Nintendo DS', 18, 6027, 6027, 6027, 34, 0, '2D Platforming', 'Sega, Dimps, Sonic Team', 'Sega', '2005-11-15', 'Sonic Rush is a 2005 platform game developed by Sonic Team and Dimps for the Nintendo DS as part of Sega''s Sonic the Hedgehog series. It was released on November 15, 2005, in North America, November 18 in the PAL region, and November 23 in Japan, and was the final game in the mainline Sonic series to be produced by Yuji Naka before his departure from Sega. It was the first Sonic game with the English 4Kids cast, instead of the cast first seen in Sonic Adventure. It is a 2D platform game, similar to earlier games in the series like Sonic Advance, as well as later ones like Sonic Mania. Levels in the game are side-scrolling and displayed using both of the DS''s screens. However, boss battles, the main characters, and a special stage are rendered in 3D, creating a 2.5D effect. The game''s storyline follows the intertwining adventures of the series'' main character, Sonic the Hedgehog and a new character, Blaze the Cat. They respectively battle Doctor Eggman and his doppelgänger Eggman Nega at certain points.', 'https://media.retroachievements.org/Images/034807.png', 'https://media.retroachievements.org/Images/028955.png', 'https://media.retroachievements.org/Images/028910.png', 'https://media.retroachievements.org/Images/038169.png', 4.9),
  (4, 14763, 'Kirby Super Star Ultra', 'Nintendo DS', 18, 5744, 5744, 5744, 50, 0, '2D Platforming', 'HAL Laboratory', 'Nintendo', '2008-09-22', 'Kirby Super Star Ultra is a 2008 anthology platform game developed by HAL Laboratory and published by Nintendo for the Nintendo DS. The game is an enhanced remake of Kirby Super Star, originally released for the Super Nintendo Entertainment System in 1996, to commemorate the Kirby series'' 15th anniversary. The remake retains all game modes found in the original and adds four major new ones, along with adding updated visuals and full-motion video cutscenes.', 'https://media.retroachievements.org/Images/123005.png', 'https://media.retroachievements.org/Images/124460.png', 'https://media.retroachievements.org/Images/028627.png', 'https://media.retroachievements.org/Images/028628.png', 4.9),
  (5, 11732, 'Pokémon Platinum Version', 'Nintendo DS', 18, 5548, 5548, 5548, 101, 0, NULL, NULL, NULL, '2008-09-13', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/104787.png', 'https://media.retroachievements.org/Images/016546.png', 'https://media.retroachievements.org/Images/028629.png', 'https://media.retroachievements.org/Images/046971.png', 4.9),
  (6, 9983, 'Super Mario 64 DS', 'Nintendo DS', 18, 5352, 5352, 5352, 191, 0, '3D Platforming, Collect-a-thon', NULL, 'Nintendo', '2004-11-21', 'Super Mario 64 DS is an enhanced remake of the 1996 platform game Super Mario 64, developed and published by Nintendo for the Nintendo DS handheld game console. As with the original title, the game''s plot centers on rescuing Princess Peach from Bowser. Players start the game with Yoshi as the playable character and gain access to Mario, Luigi, and Wario as the story progresses.', 'https://media.retroachievements.org/Images/070042.png', 'https://media.retroachievements.org/Images/027923.png', 'https://media.retroachievements.org/Images/028674.png', 'https://media.retroachievements.org/Images/028769.png', 4.8),
  (7, 9878, 'Tetris DS', 'Nintendo DS', 18, 5061, 5061, 5061, 102, 0, NULL, NULL, 'Nintendo', '2006-03-20', 'Tetris DS is a puzzle video game developed and published by Nintendo. It was released for the Nintendo DS on March 20, 2006, in North America, April 13, 2006, in Australia, April 21, 2006, in Europe, and April 27, 2006, in Japan. An installment of the Tetris franchise, the game supports up to ten players locally, and supported online multiplayer of up to four players using Nintendo Wi-Fi Connection prior to its discontinuation.', 'https://media.retroachievements.org/Images/059744.png', 'https://media.retroachievements.org/Images/043276.png', 'https://media.retroachievements.org/Images/043278.png', 'https://media.retroachievements.org/Images/043277.png', 4.8),
  (8, 16211, 'Pokémon White Version', 'Nintendo DS', 18, 4188, 4188, 4188, 73, 0, NULL, NULL, NULL, '2010-09-18', 'Pokémon Black Version and Pokémon White Version are 2010 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Nintendo DS. They are the first installments in the fifth generation of the Pokémon video game series. First released in Japan on 18 September 2010, they were later released in Europe, North America and Australia in 2011. Sequels to Black and White, Pokémon Black 2 and Pokémon White 2, were released for the Nintendo DS in 2012.', 'https://media.retroachievements.org/Images/104481.png', 'https://media.retroachievements.org/Images/032988.png', 'https://media.retroachievements.org/Images/033230.png', 'https://media.retroachievements.org/Images/033229.png', 4.8),
  (9, 12711, 'Mario Kart DS', 'Nintendo DS', 18, 4183, 4183, 4183, 100, 0, 'Kart Racing', NULL, 'Nintendo', '2005-11-14', 'Mario Kart DS is a 2005 kart racing game developed and published by Nintendo for the Nintendo DS handheld game console. Like other games in the series, Mario Kart DS features characters from the Mario series and pits them against each other as they race in karts on tracks based on locations in the Mario series. It was released in November 2005 in North America, Europe, and Australia, and on December 8, 2005, in Japan, and rereleased for the Wii U''s Virtual Console in North America and PAL regions in April 2015 and in Japan in May 2016. The game is the fifth main entry in the Mario Kart series, and the first playable via the Nintendo Wi-Fi Connection online service.', 'https://media.retroachievements.org/Images/072928.png', 'https://media.retroachievements.org/Images/028717.png', 'https://media.retroachievements.org/Images/028624.png', 'https://media.retroachievements.org/Images/028623.png', 4.8),
  (10, 12747, 'Phoenix Wright: Ace Attorney', 'Nintendo DS', 18, 3283, 3283, 3283, 83, 0, 'Visual Novel', 'Capcom', 'Capcom', '2005-10-12', 'Phoenix Wright: Ace Attorney is a visual novel adventure game developed and published by Capcom. It was released in 2001 for the Game Boy Advance in Japan and has been ported to multiple platforms. The 2005 Nintendo DS version, titled Gyakuten Saiban Yomigaeru Gyakuten in Japan, introduced an English language option, and was the first time the game was released in North America and Europe. It is the first entry in the Ace Attorney series; several sequels and spin-offs were produced, while this game has seen further ports and remasters for computers, game consoles, and mobile devices.', 'https://media.retroachievements.org/Images/060426.png', 'https://media.retroachievements.org/Images/030508.png', 'https://media.retroachievements.org/Images/053621.png', 'https://media.retroachievements.org/Images/053629.png', 4.7),
  (11, 14700, 'Kirby: Squeak Squad', 'Nintendo DS', 18, 3187, 3187, 3187, 86, 0, '2D Platforming', 'Flagship, HAL Laboratory', 'Nintendo', '2006-11-02', 'Kirby: Squeak Squad is a 2006  platform game developed by HAL Laboratory and Flagship and published by Nintendo for the Nintendo DS. It is one of the mainline installment entries of the Kirby series and the second Kirby game released for the system. The game was released in Japan and North America in 2006 and in Europe, Australia, and South Korea in 2007. The game was later re-released for the Wii U''s Virtual Console on June 25, 2015.', 'https://media.retroachievements.org/Images/111488.png', 'https://media.retroachievements.org/Images/027844.png', 'https://media.retroachievements.org/Images/043283.png', 'https://media.retroachievements.org/Images/043284.png', 4.7),
  (12, 14853, 'Pokémon Mystery Dungeon: Explorers of Sky', 'Nintendo DS', 18, 2933, 2933, 2933, 128, 0, 'Roguelike', 'Chunsoft', 'Nintendo', '2009-04-18', 'Pokémon Mystery Dungeon: Explorers of Sky is an enhanced version of Pokémon Mystery Dungeon: Explorers of Time and Explorers of Darkness released for the Nintendo DS in 2009, developed by Chunsoft and published by The Pokémon Company and Nintendo. Referred to as the definitive edition to the aforementioned games, additional features include the addition of the missing Generation IV Pokémon, further character development for a few side characters in content known as Special Episodes, and a few quality of life improvement for options, items, and other gameplay and system related features.', 'https://media.retroachievements.org/Images/042484.png', 'https://media.retroachievements.org/Images/039517.png', 'https://media.retroachievements.org/Images/039514.png', 'https://media.retroachievements.org/Images/039515.png', 4.7),
  (13, 9407, 'Castlevania: Portrait of Ruin', 'Nintendo DS', 18, 2873, 2873, 2873, 88, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2006-12-05', 'Castlevania: Portrait of Ruin is a 2006 action role-playing game developed and published by Konami for the Nintendo DS handheld system. The game is the first in the Castlevania series to feature a cooperative multiplayer gameplay mode and the first handheld entry to have English voice-overs, outside of its original Japanese release.', 'https://media.retroachievements.org/Images/105113.png', 'https://media.retroachievements.org/Images/071799.png', 'https://media.retroachievements.org/Images/071801.png', 'https://media.retroachievements.org/Images/071800.png', 4.7),
  (14, 9518, 'Professor Layton and the Curious Village', 'Nintendo DS', 18, 2838, 2838, 2838, 42, 0, NULL, NULL, NULL, '2007-02-15', 'Professor Layton and the Curious Village is a puzzle adventure video game for the Nintendo DS system. It was developed and published by Level-5 in Japan and published by Nintendo worldwide. It was released in Japan in 2007 and worldwide the following year. It was re-released in Australia using the British English localisation and European artwork to replace the previously released North American localisation. Curious Village is the first game in the Professor Layton series, followed by Professor Layton and the Diabolical Box. An enhanced mobile port of Curious Village featuring additional cutscenes, subtitled "HD for Mobile", was released in 2018.', 'https://media.retroachievements.org/Images/068336.png', 'https://media.retroachievements.org/Images/027863.png', 'https://media.retroachievements.org/Images/028672.png', 'https://media.retroachievements.org/Images/028673.png', 4.7),
  (15, 7010, 'Castlevania: Order of Ecclesia', 'Nintendo DS', 18, 2747, 2747, 2747, 94, 0, 'Metroidvania, 2D Platforming', 'Konami', 'Konami', '2008-10-21', 'Castlevania: Order of Ecclesia is a 2008 action role-playing game and the third Nintendo DS installment of the Castlevania franchise. It was directed by Akihiro Minakata, with producer Koji Igarashi returning. The plot involves Shanoa, who is part of an organization set to defeat Dracula after the Belmont clan has vanished.', 'https://media.retroachievements.org/Images/106340.png', 'https://media.retroachievements.org/Images/071796.png', 'https://media.retroachievements.org/Images/071798.png', 'https://media.retroachievements.org/Images/071797.png', 4.7),
  (16, 12718, 'Plants vs. Zombies', 'Nintendo DS', 18, 2652, 2652, 2652, 64, 0, 'Tower Defense', 'TOSE, PopCap Games', 'PopCap Games', '2011-01-18', 'Plants vs. Zombies is a video game franchise created by George Fan. The series follows the affiliates of David "Crazy Dave" Blazing as they use his plants to defend against a zombie invasion, led by Dr. Edgar George Zomboss. The first game, Plants vs. Zombies (2009), was developed by PopCap Seattle and released by PopCap Games before being acquired by Electronic Arts (EA). After PopCap Games'' acquisition, EA expanded the game into a franchise with games on many different platforms, including a comic book series written by Paul Tobin and published by Dark Horse Comics.', 'https://media.retroachievements.org/Images/074637.png', 'https://media.retroachievements.org/Images/034121.png', 'https://media.retroachievements.org/Images/034188.png', 'https://media.retroachievements.org/Images/034189.png', 4.7),
  (17, 5323, 'Mario & Luigi: Bowser''s Inside Story', 'Nintendo DS', 18, 2410, 2410, 2410, 109, 0, 'Turn-Based RPG', 'AlphaDream', 'Nintendo', '2009-02-11', 'Mario & Luigi: Bowser''s Inside Story is a 2009 role-playing video game developed by AlphaDream and published by Nintendo for the Nintendo DS. It is the third game in the Mario & Luigi series, following Partners in Time (2005). It uses the interactive screens of the DS in some of its gameplay mechanics while also introducing several elements that would be used in the series'' future gameplay.', 'https://media.retroachievements.org/Images/112160.png', 'https://media.retroachievements.org/Images/030585.png', 'https://media.retroachievements.org/Images/031522.png', 'https://media.retroachievements.org/Images/044708.png', 4.7),
  (18, 5853, 'Pokémon Black Version 2', 'Nintendo DS', 18, 2391, 2391, 2391, 187, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo, The Pokémon Company', '2012-06-23', 'Pokémon Black Version 2 and Pokémon White Version 2 are 2012 role-playing video games developed by Game Freak, published by The Pokémon Company and Nintendo for the Nintendo DS. Part of the fifth generation of the Pokémon video game series, the games are direct sequels to Pokémon Black and Pokémon White, being the first sequels in the series. They were first released in Japan in June 2012, with a worldwide release following in October 2012, as the last first-party games for the system. The games feature the legendary Pokémon identified by Junichi Masuda as Black Kyurem and White Kyurem. The games were first revealed on February 26, 2012, in the episode of the Japanese television program Pokémon Smash!, followed by an international confirmation on the Pokémon official website.', 'https://media.retroachievements.org/Images/105979.png', 'https://media.retroachievements.org/Images/062584.png', 'https://media.retroachievements.org/Images/080689.png', 'https://media.retroachievements.org/Images/073466.png', 4.7),
  (19, 9594, 'Animal Crossing: Wild World', 'Nintendo DS', 18, 2175, 2175, 2175, 157, 0, 'Life Simulation', NULL, 'Nintendo', '2005-11-23', 'Animal Crossing: Wild World is a 2005 social simulation video game developed and published by Nintendo for the Nintendo DS handheld game console. It was released in Japan in November 2005, in North America and Australia in December 2005, and in Europe in March 2006. It is the second installment in the Animal Crossing series, and the sequel to Animal Crossing on the GameCube.', 'https://media.retroachievements.org/Images/071904.png', 'https://media.retroachievements.org/Images/039333.png', 'https://media.retroachievements.org/Images/039293.png', 'https://media.retroachievements.org/Images/042440.png', 4.6),
  (20, 14811, 'Sonic & Sega All-Stars Racing', 'Nintendo DS', 18, 2130, 2130, 2130, 99, 0, 'Kart Racing', 'Sumo Digital', 'Sega', '2010-02-23', 'Sonic & Sega All-Stars Racing is a 2010 kart racing video game developed by Sumo Digital and published by Sega. It was released for Wii, Xbox 360, PlayStation 3, Nintendo DS, and Windows, featuring characters from multiple Sega franchises. The game is the third title in the Sega All-Stars series, preceded by Sega Superstars Tennis. A mobile version was developed by Gameloft, and released for iOS in June 2011, as a paid download. A version for OS X was released by Feral Interactive in April 2013.', 'https://media.retroachievements.org/Images/038912.png', 'https://media.retroachievements.org/Images/028987.png', 'https://media.retroachievements.org/Images/028915.png', 'https://media.retroachievements.org/Images/042193.png', 4.6),
  (21, 14323, 'The Legend of Zelda: Phantom Hourglass', 'Nintendo DS', 18, 2048, 2048, 2048, 67, 0, 'Action-Adventure', NULL, 'Nintendo', '2007-06-23', 'The Legend of Zelda: Phantom Hourglass is a 2007 action-adventure game developed and published by Nintendo for the Nintendo DS handheld game console. It is the fourteenth installment in The Legend of Zelda series and the direct sequel to the 2002 GameCube game The Wind Waker. Phantom Hourglass was released worldwide in 2007, with the exception of South Korea in April 2008. It was re-released for the Wii U via the Virtual Console service in the PAL region in November 2015, in North America in May 2016, and in Japan in August 2016.', 'https://media.retroachievements.org/Images/109728.png', 'https://media.retroachievements.org/Images/067328.png', 'https://media.retroachievements.org/Images/029210.png', 'https://media.retroachievements.org/Images/042344.png', 4.6),
  (22, 9852, 'Pokémon Diamond Version', 'Nintendo DS', 18, 1902, 1902, 1902, 121, 0, NULL, NULL, NULL, '2006-09-28', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/104785.png', 'https://media.retroachievements.org/Images/027617.png', 'https://media.retroachievements.org/Images/027622.png', 'https://media.retroachievements.org/Images/027623.png', 4.6),
  (23, 14808, 'Sonic Colors', 'Nintendo DS', 18, 1896, 1896, 1896, 42, 0, '2D Platforming', 'Sega, Dimps, Sonic Team', 'Sega', '2010-11-11', 'Sonic Colors is a 2010 platform game developed by Sonic Team and published by Sega. It follows Sonic''s quest to stop his nemesis Doctor Eggman from enslaving an alien race and taking over the world. The gameplay is similar to prior Sonic games, with players collecting rings and defeating enemies; the camera perspective often switches from third-person to side-scrolling perspectives. The game also introduces Wisps, power-ups the player can use to increase attack power and reach new areas.', 'https://media.retroachievements.org/Images/114272.png', 'https://media.retroachievements.org/Images/028990.png', 'https://media.retroachievements.org/Images/045152.png', 'https://media.retroachievements.org/Images/045153.png', 4.6),
  (24, 16197, 'Pokémon White Version 2', 'Nintendo DS', 18, 1863, 1863, 1863, 151, 0, NULL, NULL, NULL, '2012-06-23', 'Pokémon Black Version 2 and Pokémon White Version 2 are 2012 role-playing video games developed by Game Freak, published by The Pokémon Company and Nintendo for the Nintendo DS. Part of the fifth generation of the Pokémon video game series, the games are direct sequels to Pokémon Black and Pokémon White, being the first sequels in the series. They were first released in Japan in June 2012, with a worldwide release following in October 2012, as the last first-party games for the system. The games feature the legendary Pokémon identified by Junichi Masuda as Black Kyurem and White Kyurem. The games were first revealed on February 26, 2012, in the episode of the Japanese television program Pokémon Smash!, followed by an international confirmation on the Pokémon official website.', 'https://media.retroachievements.org/Images/105970.png', 'https://media.retroachievements.org/Images/042704.png', 'https://media.retroachievements.org/Images/042702.png', 'https://media.retroachievements.org/Images/042703.png', 4.6),
  (25, 1199, 'WarioWare: Touched!', 'Nintendo DS', 18, 1828, 1828, 1828, 45, 0, 'Minigames', 'Intelligent Systems', 'Nintendo', '2004-12-02', 'WarioWare: Touched! is a 2004 action game developed by Nintendo SPD and Intelligent Systems and published by Nintendo for the Nintendo DS. The fourth installment of the WarioWare series, and the first of three on the Nintendo DS, the game involves rapidly completing "microgames" — simple minigames lasting extremely short periods of time — as quickly as possible. The microgames are exclusively controlled with the Nintendo DS''s touchscreen and microphone.', 'https://media.retroachievements.org/Images/039657.png', 'https://media.retroachievements.org/Images/028502.png', 'https://media.retroachievements.org/Images/028505.png', 'https://media.retroachievements.org/Images/028504.png', 4.6),
  (26, 16298, 'Ace Attorney Investigations: Miles Edgeworth', 'Nintendo DS', 18, 1766, 1766, 1766, 91, 0, 'Visual Novel', 'Capcom', 'Capcom', '2009-05-28', 'Ace Attorney Investigations: Miles Edgeworth is a 2009 adventure video game developed and published by Capcom. It was originally released for the Nintendo DS in Japan in 2009, and internationally in 2010, and later for iOS and Android in 2017. It is the fifth game in the Ace Attorney series, and is set between the events of the third and fourth games, Phoenix Wright: Ace Attorney – Trials and Tribulations and Apollo Justice: Ace Attorney.', 'https://media.retroachievements.org/Images/086579.png', 'https://media.retroachievements.org/Images/035149.png', 'https://media.retroachievements.org/Images/035147.png', 'https://media.retroachievements.org/Images/040243.png', 4.6),
  (27, 16196, '~Hack~ Pokémon Renegade Platinum', 'Nintendo DS', 18, 1699, 1699, 1699, 109, 0, 'Turn-Based RPG', 'Hacker - Drayano', 'Hack - Pokemon Platinum Version', '2019-04-18', 'The Pokémon Trading Card Game collectible card game was released in Japan in 1996. As of December 2025, there are 126 card sets for the game released in English and as of April 2022, there are 91 released in Japan, including special sets. As of September 2017, collectively, there are 6,959 cards in Japanese sets and 9,110 cards in English sets. As of March 2017, 23.6 billion cards have been shipped worldwide.', 'https://media.retroachievements.org/Images/066999.png', 'https://media.retroachievements.org/Images/067000.png', 'https://media.retroachievements.org/Images/067074.png', 'https://media.retroachievements.org/Images/067073.png', 4.6),
  (28, 16274, 'Resident Evil: Deadly Silence', 'Nintendo DS', 18, 1676, 1676, 1676, 150, 0, 'Survival Horror', 'Capcom', 'Capcom', '2006-01-19', 'Resident Evil is a 1996 survival horror video game developed and published by Capcom for the PlayStation. It is the first main installment in Capcom''s Resident Evil series. Set in the fictional Arklay mountain region in the Midwest, players control Chris Redfield and Jill Valentine, members of the elite task force S.T.A.R.S., who must escape a mansion infested with zombies and other monsters.', 'https://media.retroachievements.org/Images/047094.png', 'https://media.retroachievements.org/Images/047487.png', 'https://media.retroachievements.org/Images/034463.png', 'https://media.retroachievements.org/Images/034466.png', 4.6),
  (29, 17492, 'Pokémon Mystery Dungeon: Blue Rescue Team', 'Nintendo DS', 18, 1474, 1474, 1474, 149, 0, 'Roguelike', 'Chunsoft', 'Nintendo, The Pokémon Company', '2005-11-17', 'Pokémon Mystery Dungeon: Blue Rescue Team and Pokémon Mystery Dungeon: Red Rescue Team are a matched pair of Pokémon video games for the Nintendo DS and Game Boy Advance, respectively. The games were developed by Chunsoft and published by The Pokémon Company and Nintendo. Red Rescue Team was the last Pokémon game released for the Game Boy Advance. The two versions are mostly identical, with Blue Rescue Team taking advantage of the dual-screen features and increased graphical and sound capabilities of the Nintendo DS. The game has six Pokémon exclusive to each version. Mystery Dungeon is quite different than the main-line games, as in the Mystery Dungeon games, you play as a Pokémon, as opposed to playing as a trainer.', 'https://media.retroachievements.org/Images/044315.png', 'https://media.retroachievements.org/Images/044314.png', 'https://media.retroachievements.org/Images/047785.png', 'https://media.retroachievements.org/Images/044707.png', 4.5),
  (30, 9093, 'Dragon Quest IX: Sentinels of the Starry Skies', 'Nintendo DS', 18, 1425, 1425, 1425, 161, 0, 'Turn-Based RPG', 'Level-5', 'Nintendo', '2009-07-11', 'Dragon Quest IX: Sentinels of the Starry Skies is a 2009 role-playing video game developed by Level-5 and Square Enix for the Nintendo DS. Published by Square Enix in Japan in July 2009 and by Nintendo overseas the following year, it is the ninth mainline entry in the Dragon Quest series. The storyline follows the protagonist, a member of the angelic Celestrian race, after a disaster in their home scatters magical fruits across the mortal realm. While carrying over traditional gameplay from the rest of the series with turn-based battles, the game is the first Dragon Quest entry to feature a customizable player character, and the first to include a multiplayer mode, with the option of trading treasure maps and loaning player characters through Nintendo Wi-Fi. Online functions ended in 2014 when it ceased operations.', 'https://media.retroachievements.org/Images/038654.png', 'https://media.retroachievements.org/Images/041699.png', 'https://media.retroachievements.org/Images/043271.png', 'https://media.retroachievements.org/Images/041702.png', 4.5),
  (31, 17565, 'Drawn To Life: SpongeBob SquarePants Edition', 'Nintendo DS', 18, 1422, 1422, 1422, 42, 0, '2D Platforming, Sandbox', 'Altron', 'THQ', '2008-09-15', ' The SpongeBob SquarePants video game series is a collection of video games and arcade games based on the Nickelodeon animated television series SpongeBob SquarePants and its film series with the same name. The television series'' massive rise in popularity during the 2000s led to a myriad of video games that span different genres. Several of these games are based on concepts from specific episodes, two of which are based on theatrical releases. Some of these titles had multiple different versions developed for a variety of home consoles and handheld consoles. Until 2013, the vast majority of titles were published by THQ. From 2013 to 2015, the license for most titles was handed to Activision. The license is currently held by THQ Nordic. Video games based on the series have often received mixed reviews from critics, yet many of these titles have performed well in sales.', 'https://media.retroachievements.org/Images/124718.png', 'https://media.retroachievements.org/Images/051188.png', 'https://media.retroachievements.org/Images/077702.png', 'https://media.retroachievements.org/Images/077701.png', 4.5),
  (32, 14807, 'Sonic Rush Adventure', 'Nintendo DS', 18, 1390, 1390, 1390, 48, 0, '2D Platforming', 'Sega, Dimps, Sonic Team', 'Sega', '2007-09-13', 'Sonic Rush Adventure is a 2007 platform game developed by Dimps and Sonic Team and published by Sega for the Nintendo DS. The sequel to 2005''s Sonic Rush, it follows Sonic the Hedgehog and Tails, who are teleported to an alternate dimension and seek the help of Blaze the Cat, while battling a band of robot pirates. Gameplay is similar to prior installments in the Sonic the Hedgehog franchise, with players controlling Sonic or Blaze through a series of side-scrolling levels while collecting rings and defeating enemies. Sonic Rush Adventure deviates from prior games with its elements of sea travel, featuring boating minigames that take advantage of the DS''s touchscreen.', 'https://media.retroachievements.org/Images/063480.png', 'https://media.retroachievements.org/Images/028974.png', 'https://media.retroachievements.org/Images/028911.png', 'https://media.retroachievements.org/Images/040595.png', 4.5),
  (33, 16153, 'Digimon World DS', 'Nintendo DS', 18, 1372, 1372, 1372, 49, 0, NULL, 'BEC', 'Bandai Namco', '2006-06-15', 'Digimon World DS, known in Japan as Digimon Story , is a role-playing video game for the Nintendo DS developed by BEC and published by Bandai Namco Games. The game was released in Japan on June 15, 2006, and in North America later that year on November 8. Despite its localized title, the game shares no relation to the separate Digimon World series.', 'https://media.retroachievements.org/Images/073614.png', 'https://media.retroachievements.org/Images/045221.png', 'https://media.retroachievements.org/Images/047116.png', 'https://media.retroachievements.org/Images/047120.png', 4.5),
  (34, 14860, 'Pokémon Conquest', 'Nintendo DS', 18, 1188, 1188, 1188, 61, 0, 'Tactical RPG', 'Koei', 'The Pokémon Company', '2012-03-17', ' Pokémon Conquest, known in Japan as Pokémon + Nobunaga''s Ambition , is a 2012 tactical role-playing video game developed by Tecmo Koei and published by The Pokémon Company and Nintendo for the Nintendo DS. The game is a crossover between the Pokémon and Nobunaga''s Ambition video game series. The game was released in Japan on March 17, 2012 and was released in North America, Australia, and Europe later that year.', 'https://media.retroachievements.org/Images/035990.png', 'https://media.retroachievements.org/Images/028993.png', 'https://media.retroachievements.org/Images/028995.png', 'https://media.retroachievements.org/Images/028996.png', 4.5),
  (35, 9252, 'Super Princess Peach', 'Nintendo DS', 18, 1151, 1151, 1151, 61, 0, '2D Platforming', 'TOSE', 'Nintendo', '2005-10-20', 'Super Princess Peach is a 2005 platform game developed by Tose and published by Nintendo for the Nintendo DS. It was released in Japan in October 2005 and worldwide the following year. Super Princess Peach is the first game to feature Princess Peach as the main protagonist on a dedicated video game console and the second overall after Princess Toadstool''s Castle Run released in 1990 on the Nelsonic Game Watch.', 'https://media.retroachievements.org/Images/087666.png', 'https://media.retroachievements.org/Images/113282.png', 'https://media.retroachievements.org/Images/029111.png', 'https://media.retroachievements.org/Images/029112.png', 4.5),
  (36, 9770, 'Dragon Quest IV: Chapters of the Chosen', 'Nintendo DS', 18, 1147, 1147, 1147, 80, 0, 'Turn-Based RPG', 'ArtePiazza', 'Square Enix', '2008-09-16', 'Dragon Quest IV: Chapters of the Chosen, titled Dragon Warrior IV when initially localized to North America, is a 1990 role-playing video game, the fourth installment of the Dragon Quest video game series developed by Chunsoft and published by Enix, and the first of the Zenithian Trilogy. It was originally released for the Famicom on 11 February 1990 in Japan. A North American NES version followed in October 1992, and would be the last Dragon Quest game localized and published by Enix''s Enix America Corporation subsidiary prior to its closure in November 1995, as well as the last Dragon Quest game to be localized into English prior to the localization of Dragon Warrior Monsters in December 1999. The game was remade by Heartbeat for the PlayStation, which eventually was available as an Ultimate Hits game. The remake was ported by ArtePiazza to the Nintendo DS, released in Japan November 2007 and worldwide in September 2008. A mobile version based on the Nintendo DS remake was released in 2014 for Android and iOS.', 'https://media.retroachievements.org/Images/073137.png', 'https://media.retroachievements.org/Images/034164.png', 'https://media.retroachievements.org/Images/034165.png', 'https://media.retroachievements.org/Images/038385.png', 4.5),
  (37, 9232, 'Elite Beat Agents', 'Nintendo DS', 18, 1125, 1125, 1125, 86, 0, 'Rhythm', 'iNiS', 'Nintendo', '2006-11-06', 'Elite Beat Agents is a rhythm video game developed by iNiS and published by Nintendo for the Nintendo DS. It was released in North America, Europe and South Korea. As the second of three rhythm games developed by iNiS specifically for the DS, it is the follow-up and international counterpart to Osu! Tatakae! Ouendan, a Japanese rhythm game released in 2005, sharing many common elements with it.', 'https://media.retroachievements.org/Images/038909.png', 'https://media.retroachievements.org/Images/040339.png', 'https://media.retroachievements.org/Images/040337.png', 'https://media.retroachievements.org/Images/040338.png', 4.5),
  (38, 25369, 'Pokémon Pearl Version', 'Nintendo DS', 18, 1081, 1081, 1081, 210, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo, The Pokémon Company', '2006-09-28', 'Pokémon is a Japanese series of creature collector role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company under the Pokémon franchise. It was created by Satoshi Tajiri with assistance from Ken Sugimori. The first games, Pocket Monsters Red and Green, were released in 1996 in Japan for the Game Boy, later released outside of Japan as Pokémon Red Version and Blue Version. The main series of role-playing video games (RPGs), referred as the "core series" by their developers, has continued on each generation of Nintendo''s handhelds. The most recently released core series game, Pokémon Legends: Z-A was released on October 16, 2025 for both the Nintendo Switch and the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/104840.png', 'https://media.retroachievements.org/Images/112817.png', 'https://media.retroachievements.org/Images/080725.png', 'https://media.retroachievements.org/Images/080726.png', 4.5),
  (39, 16618, 'Doodle Jump Journey', 'Nintendo DS', 18, 1058, 1058, 1058, 12, 0, 'Endless Runner', 'Smoking Gun Interactive', 'GameMill Entertainment', '2013-10-29', 'Doodle Jump is a 2009 platformer video game developed and published by Igor and Marko Pušenjak, who make up the Lima Sky LLC. The game was released for Windows Phone, iOS, BlackBerry, Android, Java Mobile, Nokia Symbian, and Xbox 360 for the Kinect. It was released worldwide for iOS in March 2009, Android and Blackberry on March 2, 2010, Symbian on May 1, 2010, Windows Phone 7 on June 1, 2011, the iPad on September 1, 2011, and Windows Phone 8 on August 21, 2013. Since its release, the game has been generally well received.', 'https://media.retroachievements.org/Images/043333.png', 'https://media.retroachievements.org/Images/037708.png', 'https://media.retroachievements.org/Images/043331.png', 'https://media.retroachievements.org/Images/043332.png', 4.5),
  (40, 4958, 'Final Fantasy Tactics A2: Grimoire of the Rift', 'Nintendo DS', 18, 1051, 1051, 1051, 185, 0, 'Tactical RPG', 'Square Enix', 'Square Enix', '2008-06-24', 'Final Fantasy Tactics A2: Grimoire of the Rift is a 2007 tactical role-playing game developed and published by Square Enix for the Nintendo DS. Releasing in 2007 in Japan and 2008 in the West, the game is a sequel to Final Fantasy Tactics Advance and forms part of the Ivalice Alliance, a group of games set in the titular fictional universe. The game features cameo appearances from central and supporting characters from Final Fantasy XII, a title set in Ivalice.', 'https://media.retroachievements.org/Images/070806.png', 'https://media.retroachievements.org/Images/030588.png', 'https://media.retroachievements.org/Images/036020.png', 'https://media.retroachievements.org/Images/036021.png', 4.5),
  (41, 14809, 'Sonic Chronicles: The Dark Brotherhood', 'Nintendo DS', 18, 1036, 1036, 1036, 68, 0, 'Turn-Based RPG', 'BioWare', 'Sega', '2008-09-25', 'Sonic Chronicles: The Dark Brotherhood is a 2008 role-playing video game developed by BioWare and published by Sega for the Nintendo DS. It is a part of the Sonic the Hedgehog series, and is its only RPG entry. Sonic Chronicles initially focuses on the events surrounding the kidnapping of Knuckles and the disappearance of the Chaos Emeralds after the defeat of Doctor Eggman, before moving on to follow the cast of characters across two dimensions as they encounter a new ally, Shade the Echidna, and seek to stop the invasion of their world by Ix, the leader of Shade''s tribe, the Nocturnus. The game is mainly played using the DS stylus, with players either exploring the overworld, or attacking with multiple characters in combat.', 'https://media.retroachievements.org/Images/038176.png', 'https://media.retroachievements.org/Images/028975.png', 'https://media.retroachievements.org/Images/086252.png', 'https://media.retroachievements.org/Images/086253.png', 4.5),
  (42, 14786, 'Yoshi''s Island DS', 'Nintendo DS', 18, 1025, 1025, 1025, 95, 0, '2D Platforming', 'Artoon', 'Nintendo', '2006-11-13', 'Yoshi''s Island DS, known in Japan as Yoshi Island DS, is a 2006 platform game developed by Artoon and published by Nintendo for the Nintendo DS. It was released in North America and Australia in November 2006, in Europe in December 2006, and in Japan in March 2007. It is a sequel to the 1995 SNES game, Super Mario World 2: Yoshi''s Island. Announced at Nintendo''s E3 press conference in May 2006, the game was well received by critics. The game was originally to be titled Yoshi''s Island 2, though its name was changed one month before its North American release. In April and May 2015, the game was made available for the Wii U via the Virtual Console service, shortly after a Nintendo Direct presentation.', 'https://media.retroachievements.org/Images/035024.png', 'https://media.retroachievements.org/Images/028968.png', 'https://media.retroachievements.org/Images/028754.png', 'https://media.retroachievements.org/Images/034937.png', 4.5),
  (43, 9617, 'Picross 3D', 'Nintendo DS', 18, 994, 994, 994, 44, 0, 'Nonogram', 'HAL Laboratory', 'Nintendo', '2009-03-12', 'Picross 3D, known in Japan as Rittai Picross , is a puzzle video game developed by HAL Laboratory and published by Nintendo for the Nintendo DS. It was released in Japan in March 2009, in Europe in March 2010, and in North America in May 2010. It uses similar nonogram mechanics to Picross DS, but adapted to a three-dimensional environment by adding an extra axis blocks can go on. Outside Japan, the game is part of Nintendo''s Touch! Generations brand. It was also released for the Wii U''s Virtual Console in Europe and Japan in 2016 and North America in 2017. A sequel, Picross 3D: Round 2, was released for the Nintendo 3DS in Japan in October 2015, in North America in September 2016, and in Europe and Australia in December 2016.', 'https://media.retroachievements.org/Images/115219.png', 'https://media.retroachievements.org/Images/112818.png', 'https://media.retroachievements.org/Images/028736.png', 'https://media.retroachievements.org/Images/028740.png', 4.4),
  (44, 11730, 'Mario Party DS', 'Nintendo DS', 18, 982, 982, 982, 112, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2007-11-08', 'Mario Party DS is a 2007 party video game developed by Hudson Soft and published by Nintendo for the Nintendo DS. It is the second handheld game in the Mario Party series, the only one to be released for the DS, and the last to be developed by Hudson Soft, as all subsequent titles have been developed by Nintendo Cube. The game was re-released on the Virtual Console for the Wii U in 2016.', 'https://media.retroachievements.org/Images/115417.png', 'https://media.retroachievements.org/Images/019596.png', 'https://media.retroachievements.org/Images/033275.png', 'https://media.retroachievements.org/Images/036078.png', 4.4),
  (45, 9537, 'Phoenix Wright: Ace Attorney - Justice for All', 'Nintendo DS', 18, 969, 969, 969, 66, 0, 'Visual Novel', 'Capcom', 'Capcom', '2007-01-16', 'Phoenix Wright: Ace Attorney – Justice for All is a visual novel adventure video game developed and published by Capcom. It was originally released for the Game Boy Advance in 2002 in Japan, and has since been released on multiple platforms. The Nintendo DS version, initially released in 2006 in Japan, was released in English in the West in 2007. The game is the second entry in the Ace Attorney series, following Phoenix Wright: Ace Attorney.', 'https://media.retroachievements.org/Images/086532.png', 'https://media.retroachievements.org/Images/030582.png', 'https://media.retroachievements.org/Images/033186.png', 'https://media.retroachievements.org/Images/033187.png', 4.4),
  (46, 1172, 'Retro Game Challenge', 'Nintendo DS', 18, 967, 967, 967, 76, 0, NULL, 'indieszero', 'XSEED Games', '2009-02-10', 'Retro Game Challenge is a minigame compilation video game developed by indieszero and published by Namco Bandai Games for the Nintendo DS. It is based on the television series GameCenter CX, with host Shinya Arino providing significant input into the game creation process. The game was released on November 15, 2007 in Japan and February 10, 2009 in North America by Xseed Games.', 'https://media.retroachievements.org/Images/099080.png', 'https://media.retroachievements.org/Images/028632.png', 'https://media.retroachievements.org/Images/028635.png', 'https://media.retroachievements.org/Images/028636.png', 4.4),
  (47, 4911, 'Ghost Trick: Phantom Detective', 'Nintendo DS', 18, 954, 954, 954, 33, 0, 'Adventure', 'Capcom', 'Capcom', '2011-01-11', 'Ghost Trick: Phantom Detective is a 2010 puzzle adventure video game developed and published by Capcom. The story follows Sissel, an amnesiac ghost with supernatural powers, and his journey to rediscover his identity. Players solve environmental puzzles, interact with eccentric characters, and uncover the truth of Sissel''s death over the course of one night. Gameplay is split into two sections: gathering information by navigating through the city, and saving lives by traveling back in time.', 'https://media.retroachievements.org/Images/060996.png', 'https://media.retroachievements.org/Images/028650.png', 'https://media.retroachievements.org/Images/028647.png', 'https://media.retroachievements.org/Images/028648.png', 4.4),
  (48, 999, '999: Nine Hours, Nine Persons, Nine Doors', 'Nintendo DS', 18, 907, 907, 907, 23, 0, 'Visual Novel', 'Chunsoft', 'Spike, Aksys Games', '2009-12-10', '999: Nine Hours, Nine Persons, Nine Doors is a visual novel and adventure video game developed by Chunsoft. It is the first installment in the Zero Escape series, and was released in Japan in December 2009 and in North America in November 2010 for the Nintendo DS. The story follows Junpei, a college student who is abducted along with eight other people and forced to play the "Nonary Game", which puts its participants in a life-or-death situation, to escape from a sinking cruise liner. The gameplay alternates between two types of sections: Escape sections, where the player completes puzzles in escape-the-room scenarios; and Novel sections, where the player reads the game''s narrative and makes decisions that influence the story toward one of six different endings.', 'https://media.retroachievements.org/Images/093358.png', 'https://media.retroachievements.org/Images/027500.png', 'https://media.retroachievements.org/Images/029800.png', 'https://media.retroachievements.org/Images/029802.png', 4.4),
  (49, 16254, 'Dragon Quest Heroes: Rocket Slime', 'Nintendo DS', 18, 891, 891, 891, 89, 0, 'Action-Adventure', 'TOSE', 'Square Enix', '2006-09-19', 'Dragon Quest Heroes: Rocket Slime is an action-adventure game developed by Tose and published by Square Enix for the Nintendo DS handheld video game console. It is the sequel to Slime Mori Mori Dragon Quest: Shōgeki no Shippo Dan for the Game Boy Advance. It was first released in Japan, and later in North America. It is a spin-off of the Dragon Quest series.', 'https://media.retroachievements.org/Images/055622.png', 'https://media.retroachievements.org/Images/037738.png', 'https://media.retroachievements.org/Images/037737.png', 'https://media.retroachievements.org/Images/037740.png', 4.4),
  (50, 6616, 'Scribblenauts', 'Nintendo DS', 18, 863, 863, 863, 311, 0, 'Puzzle, Action', '5th Cell', 'Warner Bros. Interactive Entertainment', '2009-09-15', 'Scribblenauts is a video game series developed by 5th Cell and Shiver Entertainment and published by Warner Bros. Interactive Entertainment.', 'https://media.retroachievements.org/Images/107693.png', 'https://media.retroachievements.org/Images/045398.png', 'https://media.retroachievements.org/Images/056147.png', 'https://media.retroachievements.org/Images/056148.png', 4.4),
  (51, 15429, 'Dragon Ball Z: Supersonic Warriors 2', 'Nintendo DS', 18, 852, 852, 852, 153, 0, '2D Fighting', 'Arc System Works', 'Atari', '2005-11-20', 'Dragon Ball Z: Supersonic Warriors  is a series of fighting games based on the Dragon Ball franchise. The first game was developed by Arc System Works and Cavia and was released for the Game Boy Advance on June 22, 2004. A sequel, Supersonic Warriors 2, was released in 2005 for the Nintendo DS.', 'https://media.retroachievements.org/Images/110471.png', 'https://media.retroachievements.org/Images/054427.png', 'https://media.retroachievements.org/Images/054500.png', 'https://media.retroachievements.org/Images/054498.png', 4.4),
  (52, 16363, 'Game & Watch Collection', 'Nintendo DS', 18, 833, 833, 833, 12, 0, 'Compilation', 'Nintendo', 'Nintendo', '2006-06-28', '  This is a list of Game & Watch games released by Nintendo. Several were collected and remade as part for the Game & Watch Gallery series for Game Boy, Game Boy Color, and Game Boy Advance. They were re-released in the Nintendo Mini Classics series in the late 1990s. Digital recreations in DSiWare were released for Nintendo DSi in 2009 and for Nintendo 3DS in 2011.', 'https://media.retroachievements.org/Images/112770.png', 'https://media.retroachievements.org/Images/035123.png', 'https://media.retroachievements.org/Images/035128.png', 'https://media.retroachievements.org/Images/035129.png', 4.4),
  (53, 14829, '~Hack~ Newer Super Mario Bros. DS', 'Nintendo DS', 18, 831, 831, 831, 50, 0, '2D Platforming', 'Hacker - Newer Team', 'Hack - New Super Mario Bros.', '2017-12-25', 'Super Mario 64 DS is an enhanced remake of the 1996 platform game Super Mario 64, developed and published by Nintendo for the Nintendo DS handheld game console. As with the original title, the game''s plot centers on rescuing Princess Peach from Bowser. Players start the game with Yoshi as the playable character and gain access to Mario, Luigi, and Wario as the story progresses.', 'https://media.retroachievements.org/Images/124219.png', 'https://media.retroachievements.org/Images/041242.png', 'https://media.retroachievements.org/Images/042111.png', 'https://media.retroachievements.org/Images/028781.png', 4.4),
  (54, 5291, 'Tomodachi Collection', 'Nintendo DS', 18, 826, 826, 826, 49, 0, 'Life Simulation', 'Nintendo', 'Nintendo', '2009-06-18', 'Tomodachi Collection is a 2009 social simulation video game developed and published by Nintendo for the Nintendo DS solely in Japan. Directed by Ryutaro Takahashi, the game follows the daily interactions between user-created Miis, all of whom reside on a remote island overseen by the player.', 'https://media.retroachievements.org/Images/047122.png', 'https://media.retroachievements.org/Images/054638.png', 'https://media.retroachievements.org/Images/053979.png', 'https://media.retroachievements.org/Images/053978.png', 4.4),
  (55, 9985, 'Rhythm Heaven', 'Nintendo DS', 18, 816, 816, 816, 46, 0, 'Rhythm', NULL, 'Nintendo', '2008-07-31', 'Rhythm Heaven, known as Rhythm Paradise in PAL regions, and Rhythm World in South Korea, is a rhythm game developed and published by Nintendo for the Nintendo DS. It is the second game in Nintendo''s Rhythm Heaven series, following the Japan-only Rhythm Tengoku (2006) for the Game Boy Advance. The game was first released in Japan in July 2008, and in North America, Europe, Oceania, and South Korea throughout 2009. It is the first game in the Rhythm Heaven series to be localized outside of Japan.', 'https://media.retroachievements.org/Images/060997.png', 'https://media.retroachievements.org/Images/032533.png', 'https://media.retroachievements.org/Images/032529.png', 'https://media.retroachievements.org/Images/032530.png', 4.4),
  (56, 5626, 'Advance Wars: Dual Strike', 'Nintendo DS', 18, 805, 805, 805, 126, 0, 'Turn-Based Strategy', 'Intelligent Systems', 'Nintendo', '2005-06-23', 'Advance Wars: Dual Strike, known as Famicom Wars DS in Japan, is a turn-based strategy video game developed by Intelligent Systems and published by Nintendo for the Nintendo DS handheld game console. It is the third installment in the Advance Wars series and was released in 2005 for Japan on June 23, in North America on August 22, in Europe on September 30 and in Australia on March 22, 2006.', 'https://media.retroachievements.org/Images/033351.png', 'https://media.retroachievements.org/Images/032609.png', 'https://media.retroachievements.org/Images/032610.png', 'https://media.retroachievements.org/Images/033354.png', 4.4),
  (57, 16295, 'Pokémon Ranger', 'Nintendo DS', 18, 804, 804, 804, 58, 0, 'Action RPG', 'APE | Creatures, HAL Laboratory', 'Nintendo', '2006-03-23', 'Pokémon Ranger is an action role-playing video game developed by HAL Laboratory and Creatures Inc. and published by The Pokémon Company and Nintendo for the Nintendo DS video game console. The game was released in Japan, North America, and Australia in 2006 before releasing in Europe in 2007.', 'https://media.retroachievements.org/Images/077490.png', 'https://media.retroachievements.org/Images/040529.png', 'https://media.retroachievements.org/Images/045155.png', 'https://media.retroachievements.org/Images/040530.png', 4.4),
  (58, 17844, '~Hack~ CTGP: Nitro', 'Nintendo DS', 18, 787, 787, 787, 168, 0, 'Kart Racing', 'CTGP Nitro Team', 'Hack - Mario Kart DS', '2022-02-05', '  Unlicensed developers and fans have created unofficial media relating to the Mario franchise. Such media include video games, ROM hacks, level editors, live action adaptations, and animations.', 'https://media.retroachievements.org/Images/065335.png', 'https://media.retroachievements.org/Images/060473.png', 'https://media.retroachievements.org/Images/060481.png', 'https://media.retroachievements.org/Images/060480.png', 4.4),
  (59, 16279, '~Homebrew~ Bubble Wrap DS', 'Nintendo DS', 18, 745, 745, 745, 7, 0, 'Simulation', 'Prodigy Games', 'Prodigy Games', '2012-01-01', 'Ghost Trick: Phantom Detective is a 2010 puzzle adventure video game developed and published by Capcom. The story follows Sissel, an amnesiac ghost with supernatural powers, and his journey to rediscover his identity. Players solve environmental puzzles, interact with eccentric characters, and uncover the truth of Sissel''s death over the course of one night. Gameplay is split into two sections: gathering information by navigating through the city, and saving lives by traveling back in time.', 'https://media.retroachievements.org/Images/034527.png', 'https://media.retroachievements.org/Images/034528.png', 'https://media.retroachievements.org/Images/034525.png', 'https://media.retroachievements.org/Images/034526.png', 4.4),
  (60, 4655, 'Dragon Quest V: Hand of the Heavenly Bride', 'Nintendo DS', 18, 741, 741, 741, 74, 0, 'Turn-Based RPG', 'Chunsoft', 'Square Enix', '2008-07-17', 'Dragon Quest V: Hand of the Heavenly Bride, known in Europe as Dragon Quest: The Hand of the Heavenly Bride and in Japan as Dragon Quest V: Bride of Heaven, is a 1992 role-playing video game developed by Chunsoft and published by Enix for the Super Famicom. The fifth main installment in the Dragon Quest series, the game was the first title in the franchise to not be initially localized in North America due to programming issues.', 'https://media.retroachievements.org/Images/038655.png', 'https://media.retroachievements.org/Images/043944.png', 'https://media.retroachievements.org/Images/043946.png', 'https://media.retroachievements.org/Images/043945.png', 4.4),
  (61, 9898, 'The Legend of Zelda: Spirit Tracks', 'Nintendo DS', 18, 731, 731, 731, 70, 0, 'Action-Adventure', NULL, 'Nintendo', '2009-12-07', 'The Legend of Zelda: Spirit Tracks is a 2009 action-adventure game developed and published by Nintendo for the Nintendo DS handheld game console. Set a century after The Wind Waker and its sequel Phantom Hourglass, the storyline follows the current incarnations of Link and Princess Zelda as they explore the land of New Hyrule to prevent the awakening of the Demon King Malladus. Players navigate New Hyrule, completing quests that advance the story and solving environmental and dungeon-based puzzles, many requiring use of the DS''s touchscreen and other hardware features. Navigation between towns and dungeons is done using a train, which features its own set of mechanics and puzzles.', 'https://media.retroachievements.org/Images/046401.png', 'https://media.retroachievements.org/Images/067329.png', 'https://media.retroachievements.org/Images/034047.png', 'https://media.retroachievements.org/Images/034050.png', 4.4),
  (62, 17484, '42 All-Time Classics', 'Nintendo DS', 18, 692, 692, 692, 64, 0, 'Card Game', 'Agenda', 'Nintendo', '2005-11-03', 'Clubhouse Games is a party video game developed by Agenda and published by Nintendo for the Nintendo DS. It consists of board, card, and tabletop games from around the world. It was released across 2005 and 2006, with some games included varying between regions. A follow-up for the Nintendo Switch, Clubhouse Games: 51 Worldwide Classics, was developed by NDcube and released worldwide in June 2020.', 'https://media.retroachievements.org/Images/042422.png', 'https://media.retroachievements.org/Images/042425.png', 'https://media.retroachievements.org/Images/042423.png', 'https://media.retroachievements.org/Images/042424.png', 4.4),
  (63, 4887, 'The World Ends with You', 'Nintendo DS', 18, 691, 691, 691, 98, 0, 'Action RPG', 'Jupiter', 'Square Enix', '2007-07-26', 'The World Ends with You is an action role-playing game co-developed by Square Enix and Jupiter for the Nintendo DS. Set in the modern-day Shibuya shopping district of Tokyo, The World Ends with You features a distinctive art style and urban fantasy elements inspired by Shibuya and its youth culture. Development was inspired by elements of Jupiter''s previous handheld game, Kingdom Hearts: Chain of Memories. It was released in Japan in July 2007, and in PAL regions and North America in April 2008. Later, an enhanced port by h.a.n.d. for mobile devices was released in 2012 under the title The World Ends with You: Solo Remix, while another enhanced port for the Nintendo Switch was released worldwide in 2018 under the title The World Ends with You: Final Remix.', 'https://media.retroachievements.org/Images/077187.png', 'https://media.retroachievements.org/Images/033387.png', 'https://media.retroachievements.org/Images/036167.png', 'https://media.retroachievements.org/Images/036168.png', 4.4),
  (64, 16622, 'Inazuma Eleven', 'Nintendo DS', 18, 656, 656, 656, 71, 0, 'Role-Playing Game', 'Level-5', 'Nintendo', '2011-01-21', 'Inazuma Eleven  is a football themed media franchise created by Level-5. The franchise began with the release of Inazuma Eleven in 2008, with the game series selling over 8 million copies worldwide by 2016. In addition to video games, the franchise also includes a manga series and several anime television series and films. Most media in the franchise are not released in the Americas; exceptions include a Nintendo 3DS port of the original game, three of the anime series, and the latest game Inazuma Eleven: Victory Road.', 'https://media.retroachievements.org/Images/107150.png', 'https://media.retroachievements.org/Images/077268.png', 'https://media.retroachievements.org/Images/107108.png', 'https://media.retroachievements.org/Images/108741.png', 4.3),
  (65, 4663, 'Final Fantasy III', 'Nintendo DS', 18, 654, 654, 654, 162, 0, NULL, 'Matrix Software, Square Enix', 'Square Enix', '2007-05-04', 'Final Fantasy III is a 1990 role-playing video game developed and published by Square for the Family Computer. The third installment in the Final Fantasy series, it follows four orphans from the village of Ur who are chosen by the world''s crystals to defeat a great evil and return balance to the world. The gameplay returns to the traditional combat system of the original game, and adds a job system allowing players to switch between character classes with unique abilities.', 'https://media.retroachievements.org/Images/089330.png', 'https://media.retroachievements.org/Images/034315.png', 'https://media.retroachievements.org/Images/034314.png', 'https://media.retroachievements.org/Images/034313.png', 4.3),
  (66, 11644, 'Shin Megami Tensei: Strange Journey', 'Nintendo DS', 18, 648, 648, 648, 243, 0, 'Turn-Based RPG', 'Atlus', 'Atlus', '2009-10-08', 'Shin Megami Tensei: Strange Journey is a role-playing video game developed by Atlus and Lancarse for the Nintendo DS. It is the sixth mainline game in the Shin Megami Tensei series, which forms the core of the Megami Tensei franchise. It was released in Japan in 2009, and in North America in 2010. The story follows a special task force sent by the United Nations to investigate the Schwarzwelt, a spatial distortion that appears in Antarctica and threatens to engulf the world. Players take control of an unnamed protagonist, navigating the environments of the Schwarzwelt in first-person. Combat involves the player and recruited demons fighting against various enemies, with the protagonist having the option of talking with and recruiting enemies. Depending on choices taken in the story, multiple endings are unlocked.', 'https://media.retroachievements.org/Images/067523.png', 'https://media.retroachievements.org/Images/033533.png', 'https://media.retroachievements.org/Images/084195.png', 'https://media.retroachievements.org/Images/084196.png', 4.3),
  (67, 6102, 'Kirby: Canvas Curse', 'Nintendo DS', 18, 624, 624, 624, 56, 0, '2D Platforming', 'HAL Laboratory', 'Nintendo', '2005-03-24', 'Kirby: Canvas Curse, known in Europe as Kirby: Power Paintbrush, is a 2005 platform game developed by HAL Laboratory and published by Nintendo for the Nintendo DS.', 'https://media.retroachievements.org/Images/120700.png', 'https://media.retroachievements.org/Images/114161.png', 'https://media.retroachievements.org/Images/035567.png', 'https://media.retroachievements.org/Images/035569.png', 4.3),
  (68, 15542, 'Metroid Prime Pinball', 'Nintendo DS', 18, 619, 619, 619, 88, 0, 'Pinball', 'Fuse Games | Silverball Studios', 'Nintendo', '2005-10-24', 'Metroid Prime Pinball is a pinball video game developed by Fuse Games and published by Nintendo for the Nintendo DS. It is a spin-off of the Metroid series, using the graphical style and various story elements from Metroid Prime. It was released in North America and Australia in 2005, in Japan in 2006, and in Europe in 2007. Metroid Prime Pinball uses the basic mechanics of pinball, along with typical pinball items. New mechanics are introduced, such as wall jumping and the ability to fire weapons. The Nintendo DS''s touchscreen can be nudged with a finger to alter the pinball''s trajectory while in motion.', 'https://media.retroachievements.org/Images/061655.png', 'https://media.retroachievements.org/Images/030244.png', 'https://media.retroachievements.org/Images/030242.png', 'https://media.retroachievements.org/Images/030243.png', 4.3),
  (69, 2642, 'Kingdom Hearts: 358/2 Days', 'Nintendo DS', 18, 611, 611, 611, 41, 0, 'Action RPG', 'h.a.n.d.', 'Square Enix', '2009-05-30', 'Kingdom Hearts 358/2 Days is an action role-playing video game developed by h.a.n.d. and Square Enix in collaboration with Disney Interactive Studios for the Nintendo DS. It is the fifth installment in the Kingdom Hearts series, and takes place near the end of the first game in parallel to Kingdom Hearts: Chain of Memories, leading directly into the events of Kingdom Hearts II. The game was released worldwide in 2009. The story is told from the perspective of Roxas, and follows his daily life within Organization XIII and his relationship with fellow Organization member Axel; it also introduces a fourteenth member, Xion, who befriends them.', 'https://media.retroachievements.org/Images/112158.png', 'https://media.retroachievements.org/Images/028678.png', 'https://media.retroachievements.org/Images/028680.png', 'https://media.retroachievements.org/Images/028679.png', 4.3),
  (70, 3103, 'Phoenix Wright: Ace Attorney - Trials and Tribulations', 'Nintendo DS', 18, 607, 607, 607, 75, 0, 'Visual Novel', 'Capcom', 'Capcom', '2007-10-23', 'Phoenix Wright: Ace Attorney – Trials and Tribulations is a visual novel adventure video game developed and published by Capcom. It was originally released for the Game Boy Advance in 2004 in Japan, and has since been released for several platforms, including a Nintendo DS version that was released in 2007 in Japan and North America and in 2008 in Europe. It is the third game in the Ace Attorney series, following Phoenix Wright: Ace Attorney (2001) and Justice for All (2002).', 'https://media.retroachievements.org/Images/060428.png', 'https://media.retroachievements.org/Images/030583.png', 'https://media.retroachievements.org/Images/090004.png', 'https://media.retroachievements.org/Images/090005.png', 4.3),
  (71, 16364, 'Game & Watch Collection 2', 'Nintendo DS', 18, 605, 605, 605, 12, 0, 'Compilation', 'Nintendo', 'Nintendo', '2008-12-15', '  This is a list of Game & Watch games released by Nintendo. Several were collected and remade as part for the Game & Watch Gallery series for Game Boy, Game Boy Color, and Game Boy Advance. They were re-released in the Nintendo Mini Classics series in the late 1990s. Digital recreations in DSiWare were released for Nintendo DSi in 2009 and for Nintendo 3DS in 2011.', 'https://media.retroachievements.org/Images/112697.png', 'https://media.retroachievements.org/Images/035124.png', 'https://media.retroachievements.org/Images/035130.png', 'https://media.retroachievements.org/Images/035131.png', 4.3),
  (72, 14813, 'Mario & Sonic at the Olympic Winter Games', 'Nintendo DS', 18, 591, 591, 591, 239, 0, NULL, NULL, NULL, '2009-10-13', 'Mario & Sonic at the Olympic Winter Games is a 2009 crossover sports video game developed and published by Sega for the Wii and Nintendo DS. Like its predecessor, it was published by Nintendo for Japan and Korea and by Sega elsewhere. Officially licensed by the International Olympic Committee (IOC) through exclusive license International Sports Multimedia, it is the first official video game of the 2010 Winter Olympic Games.', 'https://media.retroachievements.org/Images/069064.png', 'https://media.retroachievements.org/Images/028973.png', 'https://media.retroachievements.org/Images/028917.png', 'https://media.retroachievements.org/Images/029995.png', 4.3),
  (73, 16236, 'The Sims 2', 'Nintendo DS', 18, 576, 576, 576, 57, 0, 'Life Simulation', 'Amaze Entertainment, Maxis', 'Electronic Arts', '2005-10-24', 'The Sims 2 is a 2004 social simulation video game developed by Maxis and published by Electronic Arts. It is the second major title in The Sims series, and is the sequel to The Sims. The game was released for Microsoft Windows on September 14, 2004, and a port for MacOS by Aspyr was released on June 17, 2005. Eight expansion packs and nine "stuff packs" were subsequently released between 2005 and 2008. In addition, versions of The Sims 2 were released on various video game consoles, including the PlayStation 2, Xbox, Nintendo DS, and GameCube, and mobile platforms, including the Nokia Ovi Store. Unlike the original, the handheld and console versions are more storyline-based. The three handheld versions of the game are completely different among themselves, unlike the home console versions of the game, which are virtually identical to each other. A sequel, The Sims 3, was released in June 2009.', 'https://media.retroachievements.org/Images/047391.png', 'https://media.retroachievements.org/Images/047395.png', 'https://media.retroachievements.org/Images/051298.png', 'https://media.retroachievements.org/Images/051299.png', 4.3),
  (74, 9546, 'Diddy Kong Racing DS', 'Nintendo DS', 18, 559, 559, 559, 166, 0, 'Kart Racing, Collect-a-thon', 'Rare', 'Nintendo', '2007-02-05', 'Diddy Kong Racing is a 1997 kart racing game developed and published by Rare for the Nintendo 64. The game revolves around Diddy Kong and his friends'' attempt to defeat the intergalactic antagonist, a wizard pig named Wizpig, through winning a series of races. The player takes control of any of the featured characters throughout the game. Diddy Kong Racing features five worlds with four racetracks each, and the ability to drive a car, hovercraft, or pilot an aeroplane.', 'https://media.retroachievements.org/Images/047184.png', 'https://media.retroachievements.org/Images/041308.png', 'https://media.retroachievements.org/Images/041309.png', 'https://media.retroachievements.org/Images/041310.png', 4.3),
  (75, 18664, 'Big Brain Academy', 'Nintendo DS', 18, 555, 555, 555, 96, 0, 'Educational', NULL, 'Nintendo', '2005-06-30', 'Big Brain Academy is a series of puzzle video games developed and published by Nintendo. Similar to the Brain Age series, each game features a number of activities designed to test, measure, and improve the player''s mental skills. The first two games were released under the Touch! Generations brand, which has since been discontinued.', 'https://media.retroachievements.org/Images/121642.png', 'https://media.retroachievements.org/Images/053982.png', 'https://media.retroachievements.org/Images/053980.png', 'https://media.retroachievements.org/Images/053981.png', 4.3),
  (76, 15981, 'LEGO Rock Band', 'Nintendo DS', 18, 554, 554, 554, 92, 0, 'Rhythm', 'Backbone Entertainment', 'Warner Bros. Interactive Entertainment', '2009-11-03', 'Lego Rock Band is a 2009 rhythm game developed by TT Fusion in partnership with Harmonix and published by Warner Bros. Interactive Entertainment. It is the fifth console installment in the Rock Band series, while it incorporates elements from Lego video games. The game was released on 3 November 2009 for Xbox 360, PlayStation 3, and Wii home consoles in the United States. A Nintendo DS version was also developed by Backbone Entertainment.', 'https://media.retroachievements.org/Images/041002.png', 'https://media.retroachievements.org/Images/041477.png', 'https://media.retroachievements.org/Images/039326.png', 'https://media.retroachievements.org/Images/039325.png', 4.3),
  (77, 17633, 'Peggle: Dual Shot', 'Nintendo DS', 18, 539, 539, 539, 49, 0, 'Action, Pachinko', 'Q Entertainment, PopCap Games', 'PopCap Games', '2009-03-03', 'Peggle: Dual Shot is the fourth game in the Peggle series, developed by Q Entertainment and published by PopCap Games for Nintendo DS in March 2009. It is a compilation game including content from both Peggle (2007) and Peggle Nights (2008). This version of the game awards the player a star each time a purple bonus peg is hit, activating a new bonus minigame upon collecting five stars. The minigame requires that the player continually bounce a ball with pinball-like bumpers to collect diamonds and extra balls.', 'https://media.retroachievements.org/Images/108430.png', 'https://media.retroachievements.org/Images/043657.png', 'https://media.retroachievements.org/Images/043658.png', 'https://media.retroachievements.org/Images/043659.png', 4.3),
  (78, 9954, 'Grand Theft Auto: Chinatown Wars', 'Nintendo DS', 18, 507, 507, 507, 150, 0, 'Action-Adventure, Sandbox', 'Rockstar Leeds', 'Rockstar Games', '2009-03-17', 'Grand Theft Auto: Chinatown Wars is a 2009 action-adventure game developed by Rockstar Leeds in conjunction with Rockstar North and published by Rockstar Games. The game was released for the Nintendo DS in March 2009, PlayStation Portable in October 2009, iOS in January 2010, and Android and Fire OS devices in December 2014. It is the thirteenth game in the Grand Theft Auto series and a follow-up to Grand Theft Auto IV, and is the first entry to be released for handheld consoles since 2006''s Vice City Stories. Set within modern-day Liberty City, the single-player story follows young Triad member Huang Lee and his efforts to recover a sword gifted by his late father after it is stolen from him, while inadvertently becoming caught in a power struggle amongst Liberty City''s Triads.', 'https://media.retroachievements.org/Images/089902.png', 'https://media.retroachievements.org/Images/031313.png', 'https://media.retroachievements.org/Images/040552.png', 'https://media.retroachievements.org/Images/040553.png', 4.3),
  (79, 8572, 'Fire Emblem: Shadow Dragon', 'Nintendo DS', 18, 489, 489, 489, 93, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2009-02-16', 'Fire Emblem: Shadow Dragon is a tactical role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo DS. It is the eleventh installment in the Fire Emblem series and a remake of the Famicom title Fire Emblem: Shadow Dragon and the Blade of Light, the first entry in the series. It released in 2008 in Japan and Europe, and 2009 in North America and Australia.', 'https://media.retroachievements.org/Images/089609.png', 'https://media.retroachievements.org/Images/036221.png', 'https://media.retroachievements.org/Images/036219.png', 'https://media.retroachievements.org/Images/080682.png', 4.3),
  (80, 9424, 'Radiant Historia', 'Nintendo DS', 18, 482, 482, 482, 120, 0, 'Turn-Based RPG', 'Atlus, Headlock', 'Atlus', '2010-11-03', 'Radiant Historia is a role-playing video game developed by Atlus and Headlock and published by Atlus for the Nintendo DS. It was released in Japan in 2010 and in North America in 2011. An expanded remake for the Nintendo 3DS, titled Radiant Historia: Perfect Chronology, was released in Japan in 2017 and in North America and Europe the following year, with the European version being published by Deep Silver.', 'https://media.retroachievements.org/Images/034477.png', 'https://media.retroachievements.org/Images/031540.png', 'https://media.retroachievements.org/Images/031542.png', 'https://media.retroachievements.org/Images/031545.png', 4.3),
  (81, 12704, 'Rune Factory: A Fantasy Harvest Moon', 'Nintendo DS', 18, 479, 479, 479, 140, 0, 'Life Simulation', 'Neverland', 'Marvelous Interactive, Natsume', '2006-08-24', 'Rune Factory: A Fantasy Harvest Moon is a 2006 role-playing simulation game developed by Neverland and published by Marvelous Interactive Inc., Natsume Inc., and Rising Star Games for the Nintendo DS handheld video game console.', 'https://media.retroachievements.org/Images/107474.png', 'https://media.retroachievements.org/Images/016533.png', 'https://media.retroachievements.org/Images/016542.png', 'https://media.retroachievements.org/Images/016532.png', 4.3),
  (82, 14812, 'Mario & Sonic at the Olympic Games', 'Nintendo DS', 18, 472, 472, 472, 100, 0, 'Sports', 'Sega', 'Sega, Nintendo', '2008-01-17', 'Mario & Sonic at the Olympic Games is a 2007 crossover sports video game developed and published by Sega for the Wii, with Nintendo publishing it in Japan. It was released for the Nintendo DS the following year. It is the first installment in the Mario & Sonic series, a crossover between Nintendo''s Mario and Sega''s Sonic the Hedgehog series, and the first licensed crossover game to feature characters from both franchises. The first official video game of the 2008 Summer Olympic Games, it is licensed by the International Olympic Committee (IOC) through exclusive licensee International Sports Multimedia (ISM).', 'https://media.retroachievements.org/Images/108382.png', 'https://media.retroachievements.org/Images/028972.png', 'https://media.retroachievements.org/Images/029991.png', 'https://media.retroachievements.org/Images/029990.png', 4.3),
  (83, 12917, 'Contra 4', 'Nintendo DS', 18, 470, 470, 470, 45, 0, 'Run & Gun', 'WayForward', 'Konami', '2007-11-13', 'Contra 4 is a run and gun video game developed by WayForward Technologies and published by Konami for the Nintendo DS. It is the eleventh overall installment of the Contra series, and was released in North America on November 13, 2007. A mobile port was released six days later on November 19, 2007. A rerelease, called Contra 4: Redux, was released for Android in 2011.', 'https://media.retroachievements.org/Images/093937.png', 'https://media.retroachievements.org/Images/028756.png', 'https://media.retroachievements.org/Images/030850.png', 'https://media.retroachievements.org/Images/030853.png', 4.3),
  (84, 17140, 'Rock Band 3', 'Nintendo DS', 18, 455, 455, 455, 122, 0, 'Rhythm', 'Backbone Entertainment', 'MTV Games', '2010-10-26', 'Rock Band 3 is a 2010 rhythm game developed by Harmonix. The game was initially published and distributed by MTV Games and Electronic Arts, respectively, on October 26, 2010. Mad Catz took over both roles and re-released the title on November 23, 2011. It is the third main installment and the seventh console release in the Rock Band series. As with the previous titles, Rock Band 3 allows players to simulate the playing of rock music and many other subgenres using special instrument controllers mimicking lead and bass guitar, keyboard, drums, and vocals. Rock Band 3 expands upon previous games by including three-part vocal harmonies — previously used in The Beatles: Rock Band and Green Day: Rock Band — plus support for MIDI-compatible keyboards, electronic drumkits, and even use of a real guitar in "Pro" mode.', 'https://media.retroachievements.org/Images/041006.png', 'https://media.retroachievements.org/Images/040967.png', 'https://media.retroachievements.org/Images/040992.png', 'https://media.retroachievements.org/Images/040968.png', 4.3),
  (85, 9404, 'Solatorobo: Red the Hunter', 'Nintendo DS', 18, 450, 450, 450, 133, 0, 'Action RPG', 'CyberConnect2 | CyberConnect', 'XSEED Games', '2011-09-27', 'Solatorobo: Red the Hunter, originally released in Japan as Soratorobo -Sore Kara Kōda e-, is an action role-playing video game developed by CyberConnect2 and published by Namco Bandai Games for the Nintendo DS. Originally released in Japan in October 2010, an English version was released in Europe in July 2011 and Australia the following November, with a North American release in September by Xseed Games. It is the spiritual sequel to Tail Concerto, and, like its predecessor, features artwork and character designs by manga artist Nobuteru Yūki and music by Chikayo Fukuda. The game includes animated cutscenes produced by Madhouse, as well as vocal themes performed by Tomoyo Mitani.', 'https://media.retroachievements.org/Images/088320.png', 'https://media.retroachievements.org/Images/028653.png', 'https://media.retroachievements.org/Images/073286.png', 'https://media.retroachievements.org/Images/073287.png', 4.3),
  (86, 16621, 'Adventure Time: Hey Ice King! Why''d You Steal Our Garbage?!!', 'Nintendo DS', 18, 446, 446, 446, 57, 0, '2D Platforming, Metroidvania', 'WayForward', 'Bandai Namco, D3 Publisher', '2012-11-20', 'Adventure Time: Hey Ice King! Why''d You Steal Our Garbage?!! is a 2012 action-adventure game developed by WayForward Technologies and published by D3 Publisher for the Nintendo DS and Nintendo 3DS. It is based on the animated television series Adventure Time.', 'https://media.retroachievements.org/Images/112623.png', 'https://media.retroachievements.org/Images/063133.png', 'https://media.retroachievements.org/Images/063130.png', 'https://media.retroachievements.org/Images/063131.png', 4.3),
  (87, 15351, 'LEGO Star Wars: The Complete Saga', 'Nintendo DS', 18, 444, 444, 444, 50, 0, 'Action-Adventure', 'TT Fusion', 'LucasArts | Lucasfilm', '2007-11-06', 'Lego Star Wars: The Complete Saga is a 2007 Lego-themed action-adventure video game based on the Lego Star Wars line of construction toys. The game was developed by Traveller''s Tales and announced by LucasArts on 25 May 2007 at Celebration IV. It was released on 6 November 2007 in North America. The Complete Saga is a combination of its predecessors in the Lego Star Wars series,  Lego Star Wars: The Video Game (2005) and its sequel, Lego Star Wars II: The Original Trilogy (2006). The Complete Saga follows the events of the first six episodes of the Skywalker Saga.', 'https://media.retroachievements.org/Images/102668.png', 'https://media.retroachievements.org/Images/072067.png', 'https://media.retroachievements.org/Images/041475.png', 'https://media.retroachievements.org/Images/041240.png', 4.3),
  (88, 4667, 'Dementium: The Ward', 'Nintendo DS', 18, 441, 441, 441, 24, 0, 'Survival Horror', 'Renegade Kid', 'Gamecock Media Group, SouthPeak Games', '2007-10-31', 'Dementium: The Ward is a survival horror first-person shooter video game developed by Renegade Kid for the Nintendo DS. The game was released in North America on October 31, 2007, published by Gamecock Media Group. After Renegade Kid gained back the rights to the title, an enhanced version of the game was announced under the title of Dementium Remastered for the Nintendo 3DS. The remastered version was released in North America on December 3, 2015, and Europe on February 11, 2016, with the company''s successor Atooi developing remasters for additional platforms.', 'https://media.retroachievements.org/Images/053418.png', 'https://media.retroachievements.org/Images/042328.png', 'https://media.retroachievements.org/Images/048655.png', 'https://media.retroachievements.org/Images/049117.png', 4.2),
  (89, 16713, 'MapleStory DS', 'Nintendo DS', 18, 441, 441, 441, 95, 0, '2D Platforming, Action RPG', 'Nexon', 'Nexon, Nintendo', '2010-04-15', 'MapleStory DS is a role-playing video game for the Nintendo DS. It is an adaptation of the original MMORPG game for Windows titled MapleStory. The game was released on April 15, 2010 in Korea, and was developed by Nexon and published by Nexon and Nintendo of Korea. Unlike the PC version, MapleStory DS is a solely single-player game.', 'https://media.retroachievements.org/Images/073715.png', 'https://media.retroachievements.org/Images/073444.png', 'https://media.retroachievements.org/Images/073445.png', 'https://media.retroachievements.org/Images/060631.png', 4.2),
  (90, 15375, '~Hack~ Another Super Mario 3D', 'Nintendo DS', 18, 437, 437, 437, 65, 0, '3D Platforming, Collect-a-thon', 'Hacker - Newer Team', 'Hack - Super Mario 64 DS', '2014-06-26', 'Super Mario 64 DS is an enhanced remake of the 1996 platform game Super Mario 64, developed and published by Nintendo for the Nintendo DS handheld game console. As with the original title, the game''s plot centers on rescuing Princess Peach from Bowser. Players start the game with Yoshi as the playable character and gain access to Mario, Luigi, and Wario as the story progresses.', 'https://media.retroachievements.org/Images/029572.png', 'https://media.retroachievements.org/Images/029569.png', 'https://media.retroachievements.org/Images/029539.png', 'https://media.retroachievements.org/Images/029540.png', 4.2),
  (91, 14815, 'Mario vs. Donkey Kong: Mini-Land Mayhem!', 'Nintendo DS', 18, 437, 437, 437, 49, 0, 'Puzzle', NULL, 'Nintendo', '2010-11-14', 'Mario vs. Donkey Kong: Mini-Land Mayhem! is a 2010 puzzle-platform game developed by Nintendo Software Technology for the Nintendo DS. The game was released in North America on November 14, 2010 and is the fourth entry in the Mario vs. Donkey Kong series.', 'https://media.retroachievements.org/Images/045305.png', 'https://media.retroachievements.org/Images/028991.png', 'https://media.retroachievements.org/Images/028919.png', 'https://media.retroachievements.org/Images/045239.png', 4.2),
  (92, 18333, 'TrackMania DS', 'Nintendo DS', 18, 433, 433, 433, 230, 0, 'Arcade Racing', 'Firebrand Games', 'Focus Home Interactive', '2008-11-14', 'TrackMania DS is a racing video game developed by Firebrand Games. It was published by Focus Home Interactive in Europe and released for the Nintendo DS on November 14, 2008, and in the United States by Atlus USA on March 17, 2009. The game received generally favorable reviews from critics.', 'https://media.retroachievements.org/Images/109540.png', 'https://media.retroachievements.org/Images/051651.png', 'https://media.retroachievements.org/Images/051642.png', 'https://media.retroachievements.org/Images/051643.png', 4.2),
  (93, 16152, 'Digimon World Dusk', 'Nintendo DS', 18, 418, 418, 418, 75, 0, NULL, 'BEC', 'Bandai Namco', '2007-03-29', 'Digimon World Dawn and Digimon World Dusk, originally released as Digimon Story Sunburst & Moonlight  in Japan, are two role-playing video games for the Nintendo DS handheld game console released in Japan on March 29, 2007 and North America on September 18, 2007. Together, they serve as the second installment of the Digimon Story series, part of the larger Digimon franchise. Despite their western title, the games are not part of the Digimon World series.', 'https://media.retroachievements.org/Images/102521.png', 'https://media.retroachievements.org/Images/073175.png', 'https://media.retroachievements.org/Images/077203.png', 'https://media.retroachievements.org/Images/083520.png', 4.2),
  (94, 1378, 'Metroid Prime: Hunters', 'Nintendo DS', 18, 409, 409, 409, 50, 0, 'First-Person Shooter', NULL, 'Nintendo', '2006-03-20', 'Metroid Prime Hunters is a 2006 action-adventure game developed by Nintendo Software Technology and published by Nintendo for the Nintendo DS. It was released in North America in March 2006, with other territories later. The story takes place in between the events of Metroid Prime and Metroid Prime 2: Echoes. Players assume the role of series protagonist Samus Aran, who investigates a mysterious message that originated from the Alimbic Cluster and comes into contact with a legion of bounty hunters.', 'https://media.retroachievements.org/Images/107022.png', 'https://media.retroachievements.org/Images/030590.png', 'https://media.retroachievements.org/Images/036792.png', 'https://media.retroachievements.org/Images/036790.png', 4.2),
  (95, 15350, 'LEGO Star Wars II: The Original Trilogy', 'Nintendo DS', 18, 408, 408, 408, 28, 0, NULL, NULL, NULL, '2006-09-12', 'Lego Star Wars II: The Original Trilogy is a 2006 Lego-themed action-adventure game developed by Traveller''s Tales and published by LucasArts and TT Games Publishing, and is the sequel to Lego Star Wars: The Video Game (2005). Part of the Lego Star Wars series, it is based on George Lucas''s movie franchise of the same name and The Lego Group''s Lego Star Wars construction toy line. It follows the events of the first three original Star Wars films: A New Hope (1977), The Empire Strikes Back (1980), and Return of the Jedi (1983). The game allows players to assume the roles of over 50 Lego versions of characters from the film series; customized characters can also be created. Camera movement was improved from its predecessor, and the concept of "vehicle levels" was explored more thoroughly. The game was revealed at American International Toy Fair. Promotions for the game were set up at chain stores across the United States.', 'https://media.retroachievements.org/Images/069680.png', 'https://media.retroachievements.org/Images/068681.png', 'https://media.retroachievements.org/Images/068683.png', 'https://media.retroachievements.org/Images/068682.png', 4.2),
  (96, 9105, 'Advance Wars: Days of Ruin', 'Nintendo DS', 18, 404, 404, 404, 119, 0, 'Turn-Based Strategy', 'Intelligent Systems', 'Nintendo', '2008-01-21', 'Advance Wars: Days of Ruin, released as Advance Wars: Dark Conflict in Europe and Australia, is a turn-based strategy video game developed by Intelligent Systems and published by Nintendo for the Nintendo DS handheld game console. It is the fourth installment in the Advance Wars series after Advance Wars: Dual Strike and was released in 2008 for North America on January 21; in Europe on January 25; and in Australia on February 21. A Japanese release was planned under the title of Famicom Wars DS: Lost Light, but was canceled after a series of delays. It finally became available in Japan through Club Nintendo in October 2013 as a downloadable platinum status reward for the DSiWare service on the Nintendo 3DS family of systems.', 'https://media.retroachievements.org/Images/043961.png', 'https://media.retroachievements.org/Images/043223.png', 'https://media.retroachievements.org/Images/043953.png', 'https://media.retroachievements.org/Images/043952.png', 4.2),
  (97, 14816, 'WarioWare: D.I.Y.', 'Nintendo DS', 18, 392, 392, 392, 90, 0, 'Minigames', NULL, 'Nintendo', '2009-04-29', 'WarioWare D.I.Y.,, also known as WarioWare: Do It Yourself in Europe and Australia, is a minigame compilation and game creation system developed by Nintendo SPD and Intelligent Systems and published by Nintendo for the Nintendo DS. It is the seventh title in the WarioWare series and the last to be developed for the Nintendo DS family of systems. Formally revealed at Nintendo''s conference in October 2008, the game was released in Japan on April 29, 2009. It was released in 2010 in North America, Europe, and Australia respectively and was accompanied by a separate WiiWare title, WarioWare: D.I.Y. Showcase.', 'https://media.retroachievements.org/Images/059844.png', 'https://media.retroachievements.org/Images/028984.png', 'https://media.retroachievements.org/Images/028920.png', 'https://media.retroachievements.org/Images/042254.png', 4.2),
  (98, 6091, 'Bejeweled 3', 'Nintendo DS', 18, 391, 391, 391, 76, 0, 'Tile Matching', 'PopCap Games, Griptonite Games', 'PopCap Games', '2011-10-19', 'Bejeweled 3 is a tile-matching puzzle video game developed and published by PopCap Games. It is the fifth game in the Bejeweled series following Bejeweled Blitz (2010) and succeeds Bejeweled 2 (2004) as the latest mainline title in the Bejeweled series. It was released for Windows and Mac OS X on December 7, 2010, as part of the 10 Years of Bejeweled celebration, which celebrated the 10th anniversary of the original Bejeweled (2000); it was ported to several other consoles afterward.', 'https://media.retroachievements.org/Images/089483.png', 'https://media.retroachievements.org/Images/038508.png', 'https://media.retroachievements.org/Images/038507.png', 'https://media.retroachievements.org/Images/089944.png', 4.2),
  (99, 9496, 'Flower, Sun, and Rain: Murder and Mystery in Paradise', 'Nintendo DS', 18, 385, 385, 385, 51, 0, 'Adventure', 'h.a.n.d., Grasshopper Manufacture', 'Rising Star Games', '2008-03-06', 'Flower, Sun, and Rain is an adventure video game developed by Grasshopper Manufacture and published by Victor Interactive Software for the PlayStation 2 in 2001. It was initially only released in Japan. A port for the Nintendo DS (DS) was developed by h.a.n.d. under supervision by Grasshopper Manufacture. It was published by Marvelous Entertainment in Japan (2008) and North America (2009) and Rising Star Games in Europe (2008).', 'https://media.retroachievements.org/Images/051467.png', 'https://media.retroachievements.org/Images/029061.png', 'https://media.retroachievements.org/Images/029062.png', 'https://media.retroachievements.org/Images/029063.png', 4.2),
  (100, 6907, 'Trauma Center: Under the Knife', 'Nintendo DS', 18, 372, 372, 372, 51, 0, 'Simulation', 'Atlus', 'Atlus', '2005-10-04', 'Trauma Center: Under the Knife is a simulation video game developed by Atlus for the Nintendo DS. The debut entry in the Trauma Center series, it was published in Japan and North America by Atlus in 2005, and by Nintendo in Europe in 2006. Set in a near future where medical science can cure previously incurable diseases, the world''s population panics when a new manmade disease called GUILT begins to spread. Doctor Derek Stiles, a surgeon possessing a mystical "Healing Touch", works with the medical research organization Caduceus to find a cure to GUILT. The gameplay combines surgery-based simulation relying on the DS''s touchscreen controls with a story told as a visual novel.', 'https://media.retroachievements.org/Images/107314.png', 'https://media.retroachievements.org/Images/028419.png', 'https://media.retroachievements.org/Images/028421.png', 'https://media.retroachievements.org/Images/028420.png', 4.2),
  (101, 17216, 'N+', 'Nintendo DS', 18, 370, 370, 370, 255, 0, '2D Platforming', 'Metanet Software, SilverBirch Studios', 'Atari', '2008-08-26', 'N+ is the console and handheld version of the Adobe Flash game N, which was developed by Metanet Software. N+ for Xbox Live Arcade was developed by Slick Entertainment and published by Metanet Software. Unique versions of the game were also ported separately to the PlayStation Portable and Nintendo DS by developers SilverBirch Studios and Atari. Metanet Software licensed their N IP for this deal, provided single player level design for both versions, and consulted on the project.', 'https://media.retroachievements.org/Images/084364.png', 'https://media.retroachievements.org/Images/081771.png', 'https://media.retroachievements.org/Images/081796.png', 'https://media.retroachievements.org/Images/081797.png', 4.2),
  (102, 14835, '~Homebrew~ EunHye DS', 'Nintendo DS', 18, 368, 368, 368, 6, 0, 'Jigsaw Puzzle', 'Ryu Seung-Ryul', 'Ryu Seung-Ryul', '2007-10-01', 'Sayaka Ohara  is a Japanese voice actress affiliated with Haikyō. Her major roles include Alicia Florence in Aria, Milly Ashford in Code Geass, Erza Scarlet in Fairy Tail, Irisviel in the Fate/Zero and Fate/kaleid liner Prisma Illya series, Layla Hamilton in Kaleido Star, Michiru Kaiou/Sailor Neptune in Sailor Moon Crystal, Beatrice in Umineko no Naku Koro ni, Yūko Ichihara in xxxHolic and Tsubasa Reservoir Chronicle, and the initial voice of Gammisers in episode 27-34 of Kamen Rider Ghost. She has also voiced in a variety of video games and live-action overseas dubs, and hosts a number of radio shows, many of which are related to her voice projects. In 2013, she received a Best Supporting Actress award at the 7th Seiyu Awards.', 'https://media.retroachievements.org/Images/028844.png', 'https://media.retroachievements.org/Images/028794.png', 'https://media.retroachievements.org/Images/041813.png', 'https://media.retroachievements.org/Images/041814.png', 4.2),
  (103, 9831, 'Professor Layton and the Unwound Future', 'Nintendo DS', 18, 366, 366, 366, 28, 0, NULL, NULL, NULL, '2008-11-27', 'Professor Layton and the Unwound Future, known in Europe and Australia as Professor Layton and the Lost Future, is the third game in the first trilogy of the Professor Layton puzzle game series by Level-5 and in conclusion the final game of the first trilogy. It was first released in Japan in November 2008 and was later released in North America in September 2010 and in Europe and Australia in October 2010. In the game, Layton meets an older version of his apprentice, Luke, who brings him to a terrible future he wishes him to help fix. The game received critical acclaim by critics, praise for its story, puzzles, characters, soundtrack, and has since been cited as one of the best games of the series. An enhanced mobile port of Unwound Future, subtitled "HD for Mobile", was released on July 13, 2020.', 'https://media.retroachievements.org/Images/068338.png', 'https://media.retroachievements.org/Images/033473.png', 'https://media.retroachievements.org/Images/033336.png', 'https://media.retroachievements.org/Images/033472.png', 4.2),
  (104, 17744, 'Yu-Gi-Oh! GX Spirit Caller', 'Nintendo DS', 18, 366, 366, 366, 149, 0, 'Collectible Card Game', 'Konami', 'Konami', '2006-11-30', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/084156.png', 'https://media.retroachievements.org/Images/065084.png', 'https://media.retroachievements.org/Images/067113.png', 'https://media.retroachievements.org/Images/067207.png', 4.2),
  (105, 11788, 'Golden Sun: Dark Dawn', 'Nintendo DS', 18, 364, 364, 364, 151, 0, 'Turn-Based RPG', 'Camelot Software Planning', 'Nintendo', '2010-11-29', 'Golden Sun: Dark Dawn is a 2010 role-playing video game developed by Camelot Software Planning and published by Nintendo for the Nintendo DS. The third entry in the Golden Sun series, it is set thirty years after the events of the first two games and follows the descendants of the earlier games'' heroes. Players control characters as they travel through the fictional world of Weyard. The game utilizes gameplay elements pioneered by its predecessors, primarily the use of magic called "Psynergy" to defeat enemies and discover new locations, help local populations, and find elemental djinn which can augment the player''s powers.', 'https://media.retroachievements.org/Images/102698.png', 'https://media.retroachievements.org/Images/053945.png', 'https://media.retroachievements.org/Images/031546.png', 'https://media.retroachievements.org/Images/039348.png', 4.2),
  (106, 16297, 'Ace Attorney Investigations 2: Prosecutor''s Gambit', 'Nintendo DS', 18, 361, 361, 361, 78, 0, 'Visual Novel', 'Capcom', 'Capcom', '2011-02-03', 'Ace Attorney Investigations 2: Prosecutor''s Gambit is an adventure video game developed by Capcom. It was released in Japan for the Nintendo DS in 2011 and for Android and iOS in 2017. It is the sixth entry in the Ace Attorney series, and the sequel to Ace Attorney Investigations: Miles Edgeworth (2009).', 'https://media.retroachievements.org/Images/076922.png', 'https://media.retroachievements.org/Images/040457.png', 'https://media.retroachievements.org/Images/043170.png', 'https://media.retroachievements.org/Images/043173.png', 4.2),
  (107, 9734, 'Cartoon Network Racing', 'Nintendo DS', 18, 357, 357, 357, 44, 0, 'Kart Racing', 'Firebrand Games', 'The Game Factory', '2006-12-04', 'Cartoon Network Racing is a racing video game developed by Eutechnyx for PlayStation 2 and Firebrand Games for Nintendo DS, published by Danish video game developer The Game Factory, and released on December 4, 2006, in North America, and on February 9, 2007, in Europe. The gameplay is similar to Nintendo''s 2003 game Mario Kart: Double Dash, but the characters and racetracks are all from six of Cartoon Network''s original animated television series: Courage the Cowardly Dog, Cow and Chicken, Dexter''s Laboratory, I Am Weasel, Johnny Bravo, and The Powerpuff Girls.', 'https://media.retroachievements.org/Images/110039.png', 'https://media.retroachievements.org/Images/054253.png', 'https://media.retroachievements.org/Images/053631.png', 'https://media.retroachievements.org/Images/053632.png', 4.2),
  (108, 1226, 'Osu! Tatakae! Ouendan', 'Nintendo DS', 18, 350, 350, 350, 70, 0, 'Rhythm', 'iNiS', 'Nintendo', '2005-07-28', 'Osu! Tatakae! Ouendan, or Ouendan, is a rhythm video game developed by iNiS and published by Nintendo for the Nintendo DS handheld game console in 2005, for release only in Japan. Ouendan stars a cheer squad rhythmically cheering for various troubled people, presented in-game in the style of a manga comic. In each stage, players use the DS touchscreen to tap specifically marked spots that appear in rhythm to various Japanese pop songs, scoring points for accurate timing and avoiding a poor performance which can cause the stage to end prematurely. Though never released in Western markets, it was a popular import to these regions, leading to the development of the Westernized Elite Beat Agents, as well as a Japan-only sequel Moero! Nekketsu Rhythm Damashii Osu! Tatakae! Ouendan 2.', 'https://media.retroachievements.org/Images/028617.png', 'https://media.retroachievements.org/Images/028618.png', 'https://media.retroachievements.org/Images/028616.png', 'https://media.retroachievements.org/Images/028619.png', 4.2),
  (109, 15428, 'Jump Ultimate Stars', 'Nintendo DS', 18, 345, 345, 345, 54, 0, NULL, NULL, NULL, '2006-11-23', 'Jump Ultimate Stars is a 2006 crossover fighting video game developed by Ganbarion and published by Nintendo for the Nintendo DS. It is the sequel to Jump Super Stars and adds numerous more features. The game boasts 305 characters from 41 different Shōnen manga series. Jump Ultimate Stars was released in Japan on November 23, 2006.', 'https://media.retroachievements.org/Images/041849.png', 'https://media.retroachievements.org/Images/041846.png', 'https://media.retroachievements.org/Images/041847.png', 'https://media.retroachievements.org/Images/041848.png', 4.2),
  (110, 9914, 'Etrian Odyssey', 'Nintendo DS', 18, 344, 344, 344, 70, 0, 'Dungeon Crawl, Turn-Based RPG', 'Atlus', 'Atlus, Nintendo', '2007-01-18', 'Etrian Odyssey is a dungeon crawler role-playing video game series. It is primarily developed and published by Atlus and currently owned by Sega. By 2016, the series had sold a combined total of 1.5 million copies worldwide.', 'https://media.retroachievements.org/Images/086308.png', 'https://media.retroachievements.org/Images/030447.png', 'https://media.retroachievements.org/Images/030448.png', 'https://media.retroachievements.org/Images/030449.png', 4.2),
  (111, 9260, 'Club Penguin: Elite Penguin Force', 'Nintendo DS', 18, 341, 341, 341, 29, 0, 'Point-and-Click Adventure', '1st Playable Productions', 'Disney Interactive Studios', '2008-11-25', 'Club Penguin: Elite Penguin Force is a point-and-click adventure game for the Nintendo DS based on Disney''s massively multiplayer online game Club Penguin. It was released in North America on November 25, 2008, in Europe on March 13, 2009, and in Australia on April 16, 2009. In September 2009, a Collector''s Edition was released which included upgrades to the game and extras. On June 10, 2010, Thrustmaster, a video game accessories manufacturer, created a "Full Spy Pack" inspired by the games. On March 8, 2012, a German regionalization of the Collector''s Edition was released in Germany.', 'https://media.retroachievements.org/Images/037186.png', 'https://media.retroachievements.org/Images/037187.png', 'https://media.retroachievements.org/Images/040983.png', 'https://media.retroachievements.org/Images/040984.png', 4.2),
  (112, 3110, 'Retro Game Challenge 2', 'Nintendo DS', 18, 336, 336, 336, 189, 0, 'Minigames', 'Indies Zero', 'Bandai Namco', '2009-02-26', 'Retro Game Challenge 2 is a 2009 minigame compilation video game developed by indieszero and published by Namco Bandai Games for the Nintendo DS. It is the sequel to Retro Game Challenge. Unlike its predecessor, it never saw an official Western release due to low sales. It received a fan translation to English that was released in 2014. A remaster of the first two games, named GameCenter CX: Arino no Chousenjou 1+2 REPLAY, was announced for Nintendo Switch and set to be released on February 22, 2024. At the time of the announcement, no news of English localization was announced.', 'https://media.retroachievements.org/Images/080514.png', 'https://media.retroachievements.org/Images/028981.png', 'https://media.retroachievements.org/Images/041325.png', 'https://media.retroachievements.org/Images/041326.png', 4.2),
  (113, 9443, 'Digimon World Dawn', 'Nintendo DS', 18, 332, 332, 332, 74, 0, NULL, 'BEC', 'Bandai Namco', '2007-03-29', 'Digimon World Dawn and Digimon World Dusk, originally released as Digimon Story Sunburst & Moonlight  in Japan, are two role-playing video games for the Nintendo DS handheld game console released in Japan on March 29, 2007 and North America on September 18, 2007. Together, they serve as the second installment of the Digimon Story series, part of the larger Digimon franchise. Despite their western title, the games are not part of the Digimon World series.', 'https://media.retroachievements.org/Images/102520.png', 'https://media.retroachievements.org/Images/073176.png', 'https://media.retroachievements.org/Images/072700.png', 'https://media.retroachievements.org/Images/072702.png', 4.2),
  (114, 2141, 'Brain Age: Train Your Brain in Minutes a Day!', 'Nintendo DS', 18, 331, 331, 331, 66, 0, 'Educational, Sudoku', 'Nintendo', 'Nintendo', '2005-05-19', 'Brain Age: Train Your Brain in Minutes a Day!, known as Dr Kawashima''s Brain Training: How Old Is Your Brain? in the PAL regions, is a 2005 edutainment puzzle video game by Nintendo for the Nintendo DS. It is inspired by the work of Japanese neuroscientist Ryuta Kawashima, who appears as a caricature of himself guiding the player.', 'https://media.retroachievements.org/Images/115159.png', 'https://media.retroachievements.org/Images/096950.png', 'https://media.retroachievements.org/Images/046002.png', 'https://media.retroachievements.org/Images/118206.png', 4.2),
  (115, 9994, 'Final Fantasy IV', 'Nintendo DS', 18, 325, 325, 325, 110, 0, NULL, 'Matrix Software', 'Square Enix', '2007-12-20', 'Final Fantasy IV, titled Final Fantasy II in its initial North American release, is a 1991 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the fourth main installment of the Final Fantasy series. The game''s story follows Cecil Harvey, a dark knight, as he tries to prevent the sorcerer Golbez from seizing powerful crystals and destroying the world. He is joined on this quest by a frequently changing group of allies. Final Fantasy IV introduced innovations that became staples of the Final Fantasy series and role-playing games in general. Its "Active Time Battle" system was used in five subsequent Final Fantasy games, and unlike prior games in the series, Final Fantasy IV gave each character their own unchangeable character class — although at a few points in the story, members of the cast change or evolve their vocation to suit the narrative.', 'https://media.retroachievements.org/Images/070791.png', 'https://media.retroachievements.org/Images/042247.png', 'https://media.retroachievements.org/Images/042249.png', 'https://media.retroachievements.org/Images/042248.png', 4.2),
  (116, 7601, 'Professor Layton and the Last Specter', 'Nintendo DS', 18, 325, 325, 325, 40, 0, 'Mystery, Logic Puzzle', 'Level-5', 'Nintendo', '2009-11-26', 'Professor Layton and the Last Specter, known in Europe as Professor Layton and the Spectre''s Call, is a puzzle adventure video game produced by Level-5 for the Nintendo DS handheld game console. Last Specter is the fourth game in the Professor Layton series, and is a prequel that takes place three years before the first trilogy, detailing how Professor Layton met his apprentice, Luke Triton, as well as introducing Layton''s assistant Emmy Altava.', 'https://media.retroachievements.org/Images/040979.png', 'https://media.retroachievements.org/Images/069270.png', 'https://media.retroachievements.org/Images/040901.png', 'https://media.retroachievements.org/Images/040902.png', 4.2),
  (117, 9119, 'The Legendary Starfy', 'Nintendo DS', 18, 317, 317, 317, 58, 0, '2D Platforming', 'TOSE', 'Nintendo', '2008-07-10', 'The Legendary Starfy is a video game series developed by Tose and published by Nintendo. The series began in 2002 with Densetsu no Starfy for the Game Boy Advance, and four sequels were released. For its first seven years, Starfy games were not released outside Japan. The fifth and latest game in the series was released as The Legendary Starfy in North America on June 8, 2009. In July 2024, the first three titles were officially released via the Nintendo Classics service.', 'https://media.retroachievements.org/Images/088303.png', 'https://media.retroachievements.org/Images/046595.png', 'https://media.retroachievements.org/Images/046596.png', 'https://media.retroachievements.org/Images/046597.png', 4.2),
  (118, 15740, 'Donkey Kong: Jungle Climber', 'Nintendo DS', 18, 316, 316, 316, 71, 0, '2D Platforming', 'Paon', 'Nintendo', '2007-09-10', 'Donkey Kong: Jungle Climber, also stylised as DK: Jungle Climber, is a 2007 puzzle-platform game developed by Paon and published by Nintendo for the Nintendo DS handheld video game console. It was released in Japan on August 9, 2007, and in western territories later that year. It was re-released for the Wii U''s Virtual Console in Japan and North America in July 2015 and in Europe and Australia in August.', 'https://media.retroachievements.org/Images/048774.png', 'https://media.retroachievements.org/Images/053836.png', 'https://media.retroachievements.org/Images/051668.png', 'https://media.retroachievements.org/Images/051669.png', 4.2),
  (119, 20052, 'Kikansha Thomas: DS de Hajimeru Chiiku Gakushuu', 'Nintendo DS', 18, 311, 311, 311, 21, 0, 'Minigames', 'Rocket Company', 'Rocket Company', '2008-07-24', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/109095.png', 'https://media.retroachievements.org/Images/059863.png', 'https://media.retroachievements.org/Images/109382.png', 'https://media.retroachievements.org/Images/109109.png', 4.2),
  (120, 14906, 'Adventures of Pinocchio', 'Nintendo DS', 18, 310, 310, 310, 18, 0, 'Jigsaw Puzzle, Sliding Puzzle', 'Phoenix Games', 'Phoenix Games', '2008-01-01', 'The Adventures of Pinocchio, commonly shortened to Pinocchio, is an 1883 children''s fantasy novel by Italian author Carlo Collodi. It is about the mischievous adventures of an animated marionette named Pinocchio. He faces many perils and temptations, meets characters who teach him about life, and learns goodness before he achieves his heart''s desire to become a real boy.', 'https://media.retroachievements.org/Images/036186.png', 'https://media.retroachievements.org/Images/029454.png', 'https://media.retroachievements.org/Images/029457.png', 'https://media.retroachievements.org/Images/029458.png', 4.2),
  (121, 17554, '~Hack~ Castlevania: Dawn of Dissonance - A Juste Story Mode Hack', 'Nintendo DS', 18, 309, 309, 309, 72, 0, 'Metroidvania', 'Serbagz', 'Hack - Castlevania: Dawn of Sorrow', '2021-04-04', NULL, 'https://media.retroachievements.org/Images/045746.png', 'https://media.retroachievements.org/Images/045747.png', 'https://media.retroachievements.org/Images/046526.png', 'https://media.retroachievements.org/Images/043139.png', 4.2),
  (122, 1284, 'Yu-Gi-Oh! 5D''s Stardust Accelerator: World Championship 2009', 'Nintendo DS', 18, 309, 309, 309, 163, 0, 'Collectible Card Game', 'Konami', 'Konami', '2009-03-26', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/069152.png', 'https://media.retroachievements.org/Images/069151.png', 'https://media.retroachievements.org/Images/065869.png', 'https://media.retroachievements.org/Images/086001.png', 4.2),
  (123, 22037, 'Peppa Pig: The Game', 'Nintendo DS', 18, 308, 308, 308, 11, 0, NULL, 'Asylum Entertainment', 'Pinnacle Software', '2009-08-07', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/120855.png', 'https://media.retroachievements.org/Images/066199.png', 'https://media.retroachievements.org/Images/066111.png', 'https://media.retroachievements.org/Images/066110.png', 4.2),
  (124, 9751, 'Super Robot Taisen OG Saga: Endless Frontier', 'Nintendo DS', 18, 298, 298, 298, 62, 0, 'Role-Playing Game', 'Monolith Soft', 'Atlus', '2009-04-29', 'Super Robot Taisen OG Saga: Endless Frontier  is a video game developed by Monolith Soft and published by Namco Bandai Games. It is a spin-off of the Super Robot Taisen: Original Generation series. Released on May 29, 2008 on the Nintendo DS, the title departs from the traditional tactical role-playing game elements for which the Super Robot Wars franchise is known and opts for turn-based role-playing gameplay instead.', 'https://media.retroachievements.org/Images/031614.png', 'https://media.retroachievements.org/Images/031618.png', 'https://media.retroachievements.org/Images/031616.png', 'https://media.retroachievements.org/Images/031617.png', 4.2),
  (125, 9931, 'Ragnarok DS', 'Nintendo DS', 18, 294, 294, 294, 43, 0, 'Action RPG', 'GungHo Online Entertainment', 'GungHo Online Entertainment, XSEED Games', '2008-12-18', 'Ragnarok DS, known in Japan as Ragnarok Online DS , is a Nintendo DS video game based on the MMORPG Ragnarok Online and was released in Japan on December 18, 2008. Xseed Games published the game in North America on February 16, 2010. The game was also released in South Korea in June 2009.', 'https://media.retroachievements.org/Images/040295.png', 'https://media.retroachievements.org/Images/040294.png', 'https://media.retroachievements.org/Images/041112.png', 'https://media.retroachievements.org/Images/041113.png', 4.2),
  (126, 9817, 'Mystery Dungeon: Shiren the Wanderer', 'Nintendo DS', 18, 292, 292, 292, 65, 0, 'Roguelike', 'Chunsoft', 'Sega', '2006-12-14', 'Mystery Dungeon: Shiren the Wanderer, originally released in Japan as Fushigi no Dungeon 2: Fūrai no Shiren, is a roguelike video game developed and published by Chunsoft. It is the second entry in the Mystery Dungeon series, following 1993''s Torneko no Daibōken. It was originally released for the Super Famicom in 1995 in Japan. Sega published a Nintendo DS remake in 2006 in Japan and in 2008 internationally. The remake was later ported to iOS and Android and published by Spike Chunsoft in 2019.', 'https://media.retroachievements.org/Images/071733.png', 'https://media.retroachievements.org/Images/071540.png', 'https://media.retroachievements.org/Images/028660.png', 'https://media.retroachievements.org/Images/028661.png', 4.2),
  (127, 22036, 'Peppa Pig: Fun and Games', 'Nintendo DS', 18, 290, 290, 290, 13, 0, 'Minigames', 'Asylum Entertainment', 'P2 Games', '2010-03-26', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/120856.png', 'https://media.retroachievements.org/Images/066116.png', 'https://media.retroachievements.org/Images/066117.png', 'https://media.retroachievements.org/Images/066118.png', 4.1),
  (128, 8376, 'Mega Man Zero Collection', 'Nintendo DS', 18, 289, 289, 289, 279, 0, 'Action, 2D Platforming, Compilation', 'Inti Creates', 'Capcom', '2010-06-08', 'Mega Man Zero Collection is a compilation of all four Mega Man Zero video games, which were originally released for the Game Boy Advance between 2002 and 2005. It was developed by Inti Creates and published by Capcom, and was made available worldwide in June 2010 for the Nintendo DS. The collection contains new features such as a beginner-friendly "Easy Scenario" that grants power-up items and abilities from the beginning of each game, as well as unlockable character art and the ability to display artwork on the Nintendo DS''s bottom screen as the game is played.', 'https://media.retroachievements.org/Images/053731.png', 'https://media.retroachievements.org/Images/050613.png', 'https://media.retroachievements.org/Images/052160.png', 'https://media.retroachievements.org/Images/052161.png', 4.1),
  (129, 17434, 'Nintendogs: Labrador & Friends', 'Nintendo DS', 18, 288, 288, 288, 54, 0, 'Pet Simulation', NULL, 'Nintendo', '2005-10-07', 'Nintendogs is a 2005 pet simulation video game developed and published by Nintendo for the Nintendo DS handheld video game console. It was released in Japan, and was later released in: North America, Australia, New Zealand, Europe and other regions. It was originally released in three different versions: Dachshund & Friends, Lab & Friends and Chihuahua & Friends. It has been re-released twice, first as a bundled release with a special edition Nintendo DS with a new version called Nintendogs: Best Friends and later with Nintendogs: Dalmatian & Friends.', 'https://media.retroachievements.org/Images/041959.png', 'https://media.retroachievements.org/Images/041829.png', 'https://media.retroachievements.org/Images/041831.png', 'https://media.retroachievements.org/Images/041845.png', 4.1),
  (130, 15915, 'Lost in Blue', 'Nintendo DS', 18, 284, 284, 284, 65, 0, 'Survival', 'Konami', 'Konami', '2005-08-25', 'Lost in Blue is a series of survival video games developed and published by Konami. They revolve around the main characters being castaways on a desert island and being forced to scavenge for survival. The series saw two Game Boy Color releases starting in 1999, only one of which was localized, before going on a five-year hiatus. It then saw several Nintendo DS installments, adopting a new localized name, Lost in Blue. Following the release of a Wii installment of the series, it went on hiatus until the announcement of a new entry on Nintendo Switch 2.', 'https://media.retroachievements.org/Images/120662.png', 'https://media.retroachievements.org/Images/058920.png', 'https://media.retroachievements.org/Images/058915.png', 'https://media.retroachievements.org/Images/058916.png', 4.1),
  (131, 16296, 'Pokémon Ranger: Shadows of Almia', 'Nintendo DS', 18, 284, 284, 284, 125, 0, 'Action RPG', 'APE | Creatures', 'Nintendo, The Pokémon Company', '2008-03-20', 'Pokémon Ranger: Shadows of Almia  is an action role-playing video game developed by Creatures Inc. and published by The Pokémon Company and Nintendo for the Nintendo DS video game console.', 'https://media.retroachievements.org/Images/044836.png', 'https://media.retroachievements.org/Images/045311.png', 'https://media.retroachievements.org/Images/045314.png', 'https://media.retroachievements.org/Images/045312.png', 4.1),
  (132, 17513, 'Taiko no Tatsujin DS: Touch de Dokodon!', 'Nintendo DS', 18, 283, 283, 283, 182, 0, 'Rhythm', 'Namco', 'Bandai Namco', '2007-07-26', 'Taiko no Tatsujin  is a Japanese video game series developed and published by Namco. In the games, players simulate playing a taiko drum in rhythm with music. The series has released titles for the arcade as well as for console and mobile platforms, including PlayStation 2, Advanced Pico Beena, PlayStation Portable, Nintendo DS, Wii, Nintendo 3DS, Wii U, PlayStation Vita, PlayStation 4, PlayStation 5, Nintendo Switch, Xbox One, Xbox Series X/S, Microsoft Windows, iOS, Android, and Japanese feature phones.', 'https://media.retroachievements.org/Images/056370.png', 'https://media.retroachievements.org/Images/056371.png', 'https://media.retroachievements.org/Images/042923.png', 'https://media.retroachievements.org/Images/042925.png', 4.1),
  (133, 16633, 'Final Fantasy Fables: Chocobo Tales', 'Nintendo DS', 18, 275, 275, 275, 155, 0, 'Minigames, Collectible Card Game', 'h.a.n.d.', 'Square Enix', '2007-04-03', 'Final Fantasy Fables: Chocobo Tales is a Nintendo DS adventure game developed by h.a.n.d. and published by Square Enix. It was first launched in Japan on December 14, 2006 and was released in the North American and PAL regions in the spring of 2007. A spin-off of the Final Fantasy franchise, Chocobo Tales stars a Chocobo and features a setting with common elements and creatures from its parent series.', 'https://media.retroachievements.org/Images/087757.png', 'https://media.retroachievements.org/Images/050460.png', 'https://media.retroachievements.org/Images/087754.png', 'https://media.retroachievements.org/Images/087755.png', 4.1),
  (134, 18541, '~Hack~ Box Adventure', 'Nintendo DS', 18, 273, 273, 273, 11, 0, '3D Platforming', NULL, 'Hack - Super Mario 64 DS', '2021-07-12', 'Rango is a 2011 action-adventure video game developed by Behaviour Interactive and published by Electronic Arts and Paramount Digital Entertainment for the Nintendo DS, PlayStation 3, Wii, & Xbox 360. It is a video game sequel to the 2011 movie of the same name.', 'https://media.retroachievements.org/Images/053419.png', 'https://media.retroachievements.org/Images/086298.png', 'https://media.retroachievements.org/Images/053221.png', 'https://media.retroachievements.org/Images/053220.png', 4.1),
  (135, 15736, 'Yu-Gi-Oh! Nightmare Troubadour', 'Nintendo DS', 18, 269, 269, 269, 48, 0, 'Collectible Card Game', 'Konami', 'Konami', '2005-07-21', 'Yu-Gi-Oh! Nightmare Troubadour is a 2005 video game developed and published by Konami for the Nintendo DS. It is the first game based on the Yu-Gi-Oh! trading card game and franchise released on the system.', 'https://media.retroachievements.org/Images/060125.png', 'https://media.retroachievements.org/Images/032051.png', 'https://media.retroachievements.org/Images/031988.png', 'https://media.retroachievements.org/Images/031987.png', 4.1),
  (136, 9462, 'Meteos', 'Nintendo DS', 18, 266, 266, 266, 80, 0, NULL, 'Q Entertainment', NULL, '2005-03-10', 'Meteos is a 2005 tile-matching video game developed by Q Entertainment and published by Bandai for the Nintendo DS. Nintendo released the game outside Japan. It was produced by Q Entertainment founder Tetsuya Mizuguchi and designed by Masahiro Sakurai. Meteos was inspired by the video game Missile Command (1980), the film The Matrix (1999) and the television series 24 (2001-2010).', 'https://media.retroachievements.org/Images/061688.png', 'https://media.retroachievements.org/Images/041635.png', 'https://media.retroachievements.org/Images/041636.png', 'https://media.retroachievements.org/Images/041637.png', 4.1),
  (137, 23701, '~Hack~ Mega Man Star Force DX', 'Nintendo DS', 18, 251, 251, 251, 79, 0, 'Action RPG', 'The Rockman EXE Zone', 'Hack - Mega Man Star Force', '2021-05-29', 'Mega Man Battle Network 6: Cybeast Gregar and Mega Man Battle Network 6: Cybeast Falzar are 2005 tactical role-playing games developed and published by Capcom for the Game Boy Advance (GBA) handheld game console. They are the sixth and final game in the Mega Man Battle Network series, and involves Lan Hikari''s family and MegaMan.EXE moving to Cyber City, only to need to once again stop the returning WWW and their plans to re-awaken the Cybeasts.', 'https://media.retroachievements.org/Images/125158.png', 'https://media.retroachievements.org/Images/070202.png', 'https://media.retroachievements.org/Images/077871.png', 'https://media.retroachievements.org/Images/077872.png', 4.1),
  (138, 7370, 'Viva Piñata: Pocket Paradise', 'Nintendo DS', 18, 249, 249, 249, 87, 0, 'Life Simulation', 'Rare', 'THQ', '2008-09-05', 'Viva Piñata: Pocket Paradise is a life simulation game developed by Rare, for the Nintendo DS video game console and based on Viva Piñata. Released days after Viva Piñata: Trouble in Paradise for the Xbox 360 in the fall of 2008, Pocket Paradise was developed by Rare''s handheld team, as opposed to Viva Piñata: Party Animals and the PC version of the original game, which were developed by separate third-party developers. It is currently the latest game Rare developed for a Nintendo system, as well as currently the final game in the series and is also the only game of the series as a whole to be handheld.', 'https://media.retroachievements.org/Images/046859.png', 'https://media.retroachievements.org/Images/046861.png', 'https://media.retroachievements.org/Images/046853.png', 'https://media.retroachievements.org/Images/046854.png', 4.1),
  (139, 14907, 'Peter Pan''s Playground', 'Nintendo DS', 18, 245, 245, 245, 8, 0, 'Jigsaw Puzzle, Sliding Puzzle', 'Phoenix Games', 'Phoenix Games', '2008-01-01', 'Peter Pan''s Playground was an amusement park in the coastal resort of Worthing, West Sussex, England for young children under 11 years of age', 'https://media.retroachievements.org/Images/029367.png', 'https://media.retroachievements.org/Images/029368.png', 'https://media.retroachievements.org/Images/029369.png', 'https://media.retroachievements.org/Images/029366.png', 4.1),
  (140, 16710, 'Ketsui Death Label: Kizuna Jigoku Tachi', 'Nintendo DS', 18, 242, 242, 242, 54, 0, 'Shoot ''em Up, Bullet Hell', 'CAVE Interactive', 'Arika', '2008-10-23', 'Ketsui: Kizuna Jigoku Tachi  is a 2003 vertical shoot ''em up arcade game by Cave, released in Japanese arcades. A Nintendo DS boss rush version was released in October 2008 in Japan. It included a Superplay DVD featuring a world record scoring run by a top ranked player. The arcade game was ported to the Xbox 360 and released in 2010. A special version of Dodonpachi Daifukkatsu Black Label was released on the Xbox 360 in 2011, which is a crossover with Ketsui, featuring the ship, re-arranged music and scoring system from Ketsui on top of the Dodonpachi Daifukkatsu Black Label scoring system.', 'https://media.retroachievements.org/Images/038001.png', 'https://media.retroachievements.org/Images/038000.png', 'https://media.retroachievements.org/Images/037996.png', 'https://media.retroachievements.org/Images/037997.png', 4.1),
  (141, 6032, 'Hotel Dusk: Room 215', 'Nintendo DS', 18, 236, 236, 236, 20, 0, 'Point-and-Click Adventure', 'Cing', 'Nintendo', '2007-01-22', 'Hotel Dusk: Room 215 (known in Japan as Wish Room: Angel''s Memory  is a point-and-click adventure game for the Nintendo DS. Originally called Wish Room, the game debuted at E3 on May 9, 2006. It was initially released in North America on January 22, 2007, and later internationally. The game supports the Nintendo DS Rumble Pak accessory.', 'https://media.retroachievements.org/Images/117254.png', 'https://media.retroachievements.org/Images/098885.png', 'https://media.retroachievements.org/Images/036351.png', 'https://media.retroachievements.org/Images/036352.png', 4.1),
  (142, 16383, 'Super Scribblenauts', 'Nintendo DS', 18, 235, 235, 235, 26, 0, 'Puzzle, Action', '5th Cell', 'Warner Bros. Interactive Entertainment', '2010-10-12', 'Super Scribblenauts is an emergent action puzzle game developed by 5th Cell and published by Warner Bros. Interactive Entertainment for the Nintendo DS handheld game console. The game was released on October 12, 2010. It is the sequel to the Nintendo DS game Scribblenauts.', 'https://media.retroachievements.org/Images/107694.png', 'https://media.retroachievements.org/Images/043377.png', 'https://media.retroachievements.org/Images/049251.png', 'https://media.retroachievements.org/Images/049250.png', 4.1),
  (143, 33170, '~Prototype~ Crash Landed', 'Nintendo DS', 18, 230, 230, 230, 6, 0, NULL, NULL, NULL, '2009-07-31', '"Crash Landed" is the second single from pop music project Sweetbox on the album The Next Generation, featuring Jamie Pineda as frontwoman. Georgie Dennis, Tom Barnes, Gavin Jones, Ben Kohn and Peter Kelleher co-wrote the song with Jamie.', 'https://media.retroachievements.org/Images/112694.png', 'https://media.retroachievements.org/Images/118901.png', 'https://media.retroachievements.org/Images/121244.png', 'https://media.retroachievements.org/Images/116565.png', 4.1),
  (144, 22844, 'Arkanoid DS', 'Nintendo DS', 18, 229, 229, 229, 133, 0, 'Brick Breakers', 'Taito', 'Taito, Square Enix', '2008-07-17', 'Arkanoid DS is a breakout video game developed and published by Taito for the Nintendo DS, with Square Enix handling publication outside Japan. It was released on December 6, 2007.', 'https://media.retroachievements.org/Images/069512.png', 'https://media.retroachievements.org/Images/069510.png', 'https://media.retroachievements.org/Images/069508.png', 'https://media.retroachievements.org/Images/069509.png', 4.1),
  (145, 5656, 'Batman: The Brave and The Bold - The Videogame', 'Nintendo DS', 18, 229, 229, 229, 69, 0, 'Beat ''em Up', 'WayForward', 'Warner Bros. Interactive Entertainment', '2010-09-07', 'Batman: The Brave and the Bold – The Videogame is a video game based on the comic book character Batman and the television cartoon series Batman: The Brave and the Bold. It was developed by WayForward Technologies and distributed by Warner Bros. Interactive Entertainment. It was released on September 7, 2010, for the Wii and Nintendo DS, and is the only non-Lego Batman video game released for those platforms.', 'https://media.retroachievements.org/Images/111019.png', 'https://media.retroachievements.org/Images/111013.png', 'https://media.retroachievements.org/Images/111010.png', 'https://media.retroachievements.org/Images/111011.png', 4.1),
  (146, 22038, 'Peppa Pig: Theme Park Fun', 'Nintendo DS', 18, 229, 229, 229, 26, 0, NULL, 'Strawdog Studios', 'P2 Games', '2011-03-25', 'Peppa Pig is a British preschool animated children''s television series created by Neville Astley and Mark Baker. Produced by Hasbro Entertainment and Karrot Animation and formerly Astley Baker Davies, the series follows Peppa, an anthropomorphic piglet, and her family and friends portrayed as other animals. The show first aired on 31 May 2004. The ninth series began broadcasting in summer 2025. Peppa Pig has been broadcast in over 180 countries.', 'https://media.retroachievements.org/Images/120857.png', 'https://media.retroachievements.org/Images/066198.png', 'https://media.retroachievements.org/Images/066122.png', 'https://media.retroachievements.org/Images/066121.png', 4.1),
  (147, 1409, 'Spider-Man: Shattered Dimensions', 'Nintendo DS', 18, 228, 228, 228, 45, 0, 'Beat ''em Up, Metroidvania', 'Griptonite Games', 'Activision', '2010-09-07', 'Spider-Man: Shattered Dimensions is a 2010 action-adventure video game based on the Marvel Comics superhero Spider-Man, developed by Beenox and published by Activision. Players control four different versions of Spider-Man, each originating from a different universe in the Marvel Comics multiverse. Previous Spider-Man voice actors Neil Patrick Harris, Christopher Daniel Barnes, Dan Gilvezan, and Josh Keaton each voice one of the four Spider-Men. The Nintendo DS version of the game was developed by Griptonite Games and features only three Spider-Man variants.', 'https://media.retroachievements.org/Images/051178.png', 'https://media.retroachievements.org/Images/028870.png', 'https://media.retroachievements.org/Images/028883.png', 'https://media.retroachievements.org/Images/051156.png', 4.1),
  (148, 7062, 'Giana Sisters DS', 'Nintendo DS', 18, 226, 226, 226, 56, 0, '2D Platforming', 'Bitfield', 'DTP Entertainment', '2009-04-03', 'Giana Sisters DS, also known on other handheld platforms as Giana Sisters, is a platform game developed by Spellbound Entertainment in cooperation with Bitfield GmbH for the Nintendo DS, iPad, iPhone, and Android. It was published by DTP Entertainment in Europe and Destineer in North America. It is a spiritual sequel to the 1987 Commodore 64 release The Great Giana Sisters. A version for Microsoft Windows, re-titled Giana Sisters 2D, was also released.', 'https://media.retroachievements.org/Images/039629.png', 'https://media.retroachievements.org/Images/039729.png', 'https://media.retroachievements.org/Images/039631.png', 'https://media.retroachievements.org/Images/039630.png', 4.1),
  (149, 19773, 'Hidden Objects: Mystery Stories', 'Nintendo DS', 18, 224, 224, 224, 43, 0, 'Hidden Object, Mystery', 'cerasus.media', 'GSP Software, Knowledge Adventure', '2009-05-29', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/069120.png', 'https://media.retroachievements.org/Images/058334.png', 'https://media.retroachievements.org/Images/069118.png', 'https://media.retroachievements.org/Images/069119.png', 4.1),
  (150, 15653, 'Phantasy Star 0', 'Nintendo DS', 18, 224, 224, 224, 131, 0, 'Action RPG', 'Sonic Team', 'Sega', '2008-12-25', 'Phantasy Star 0, also known in Australia and Europe as Phantasy Star: ZERO and sometimes in North America as Phantasy Star Ø, is a Nintendo DS game in the Phantasy Star series, developed by Sonic Team and published by Sega. The game was released in Japan on December 25, 2008; in North America on November 10, 2009; and in Europe on February 12, 2010. The game expands on the gameplay mechanics of Phantasy Star Online, partly by borrowing some elements from fellow online Phantasy Star title Phantasy Star Universe, such as a fully realized story mode for offline play.', 'https://media.retroachievements.org/Images/030820.png', 'https://media.retroachievements.org/Images/030706.png', 'https://media.retroachievements.org/Images/030707.png', 'https://media.retroachievements.org/Images/030708.png', 4.1),
  (151, 25351, '~Homebrew~ The Search Master: Metal Gear Solid Edition', 'Nintendo DS', 18, 223, 223, 223, 6, 0, 'Puzzle', 'Multiple:Option', 'Multiple:Option', '2008-12-24', '2008 saw many new installments in established video game franchises, such as Grand Theft Auto IV, Fallout 3, Metal Gear Solid 4: Guns of the Patriots, Gears of War 2, Super Smash Bros. Brawl, Persona 4, Fable II, Call of Duty: World at War, Mario Kart Wii, Madden NFL 09, NBA Live 09, NBA 2K9, and WWE Smackdown vs. Raw 2009. New intellectual properties included Army of Two, Dead Space, Left 4 Dead, LittleBigPlanet, Mirror''s Edge, iRacing, Race Driver: Grid, and Spore, De Blob, Meat Boy.', 'https://media.retroachievements.org/Images/080987.png', 'https://media.retroachievements.org/Images/109202.png', 'https://media.retroachievements.org/Images/080323.png', 'https://media.retroachievements.org/Images/080324.png', 4.1),
  (152, 12712, 'Cory in the House', 'Nintendo DS', 18, 220, 220, 220, 32, 0, 'Action-Adventure', 'Handheld Games', 'Disney Interactive Studios', '2008-04-15', 'Cory in the House is an American television sitcom which aired on the Disney Channel from January 12, 2007, to September 12, 2008, and was a spin-off from the Disney Channel series That''s So Raven. The show focuses on Cory Baxter, who moves from San Francisco, California, to Washington, D.C. with his father, Victor Baxter, who gets a new job as the White House executive chef. The series was the first Disney Channel spin-off series, as well as the final Disney Channel series overall to be both shot and broadcast in standard definition for the entire run of the show. Reruns of the series have aired on Disney Channel and Disney XD, it also aired on the Family Channel in Canada. Raven-Symoné guest-starred in one episode, reprising her role as Raven Baxter.', 'https://media.retroachievements.org/Images/083680.png', 'https://media.retroachievements.org/Images/016550.png', 'https://media.retroachievements.org/Images/052325.png', 'https://media.retroachievements.org/Images/083722.png', 4.1),
  (153, 15614, 'Mario Hoops 3-on-3', 'Nintendo DS', 18, 220, 220, 220, 34, 0, NULL, 'Nintendo, Square Enix', 'Nintendo', '2006-07-27', 'Mario Hoops 3-on-3, known in Europe as Mario Slam Basketball, is a 2006 sports game developed by Square Enix and published by Nintendo for the Nintendo DS. The game is the first in which Mario and Final Fantasy characters appear together as playable characters, and the second Mario game developed by Square Enix, after Super Mario RPG (1996). It is the only dedicated basketball game in the Mario series. The game was released in Japan on July 27, 2006, North America on September 11, 2006, Australia on October 26, 2006, and Europe on February 16, 2007.', 'https://media.retroachievements.org/Images/072680.png', 'https://media.retroachievements.org/Images/114135.png', 'https://media.retroachievements.org/Images/029992.png', 'https://media.retroachievements.org/Images/029993.png', 4.1),
  (154, 16155, 'Digimon Story: Lost Evolution', 'Nintendo DS', 18, 218, 218, 218, 118, 0, NULL, 'BEC', 'Bandai Namco', '2010-07-01', 'Digimon Story: Lost Evolution is a role-playing video game published by Bandai Namco Games for the Nintendo DS. It is the third game in the Digimon Story series, part of the greater Digimon franchise. The title was released exclusively in Japan on July 1, 2010.', 'https://media.retroachievements.org/Images/073852.png', 'https://media.retroachievements.org/Images/049241.png', 'https://media.retroachievements.org/Images/049237.png', 'https://media.retroachievements.org/Images/049238.png', 4.1),
  (155, 3529, 'Nanashi no Geemu', 'Nintendo DS', 18, 218, 218, 218, 24, 0, 'Horror', 'Epics', 'Square Enix', '2008-07-03', 'epics Inc.  is a Japanese video game software developer located in Tokyo, Japan. Originally established as Gen Creative House Co., Ltd. in February 1987, changed company name to G-Artists Inc. in March 1991, then to epics Inc. in June 2006.', 'https://media.retroachievements.org/Images/036071.png', 'https://media.retroachievements.org/Images/069176.png', 'https://media.retroachievements.org/Images/036145.png', 'https://media.retroachievements.org/Images/036146.png', 4.1),
  (156, 20916, '101 in 1 Explosive Megamix', 'Nintendo DS', 18, 216, 216, 216, 107, 0, NULL, 'Nordcurrent', NULL, '2008-11-28', '101-in-1 Explosive Megamix is a video game developed by Nordcurrent and published by Atlus for the Nintendo DS. It was released in Europe on November 28, 2008 and on April 21, 2009 in North America and features 10 hours'' worth of 101 minigames. A version for the WiiWare service was released on September 22, 2011 in Europe and on October 13 in North America.', 'https://media.retroachievements.org/Images/073517.png', 'https://media.retroachievements.org/Images/073016.png', 'https://media.retroachievements.org/Images/073514.png', 'https://media.retroachievements.org/Images/073515.png', 4.1),
  (157, 15357, 'LEGO Harry Potter: Years 1-4', 'Nintendo DS', 18, 215, 215, 215, 30, 0, 'Action-Adventure', 'TT Fusion', 'Warner Bros. Interactive Entertainment', '2010-06-29', 'Lego Harry Potter: Years 1–4 is an action-adventure game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game is based on the Lego Harry Potter toy line, and its storyline covers the first four books by J. K. Rowling and its film adaptations in the Harry Potter film series, Philosopher''s Stone (2001), Chamber of Secrets (2002), Prisoner of Azkaban (2004), and Goblet of Fire (2005).', 'https://media.retroachievements.org/Images/118071.png', 'https://media.retroachievements.org/Images/043580.png', 'https://media.retroachievements.org/Images/043581.png', 'https://media.retroachievements.org/Images/043582.png', 4.1),
  (158, 15737, 'Yu-Gi-Oh! World Championship 2007', 'Nintendo DS', 18, 214, 214, 214, 52, 0, 'Collectible Card Game', 'Konami', 'Konami', '2007-03-20', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/058712.png', 'https://media.retroachievements.org/Images/031846.png', 'https://media.retroachievements.org/Images/031847.png', 'https://media.retroachievements.org/Images/031845.png', 4.1),
  (159, 17087, '~Homebrew~ Sushi the Cat DS', 'Nintendo DS', 18, 211, 211, 211, 10, 0, '2D Platforming', 'N3TKaT, Kamui', 'N3TKaT, Kamui', '2005-01-01', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/093303.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/093367.png', 'https://media.retroachievements.org/Images/093366.png', 4.1),
  (160, 20362, 'Assassin''s Creed: Altair''s Chronicles', 'Nintendo DS', 18, 209, 209, 209, 28, 0, 'Action-Adventure', 'Gameloft', NULL, '2008-02-05', 'Assassin''s Creed: Altaïr''s Chronicles is a 2008 action-adventure video game developed by Gameloft and published by Ubisoft. It is the first spin-off installment in the Assassin''s Creed franchise, and a prequel to 2007''s Assassin''s Creed. Taking place in the year 1190 AD, one year prior to the events of Assassin''s Creed, the game revolves around Altaïr Ibn-LaʼAhad''s search for an artifact called the Chalice, which brings him into conflict with the Templar Order. Altaïr travels to several cities in the Middle East during the game, including Jerusalem, Acre, and Damascus, as well as Tyre and Aleppo, which are new to the series.', 'https://media.retroachievements.org/Images/122975.png', 'https://media.retroachievements.org/Images/061172.png', 'https://media.retroachievements.org/Images/098693.png', 'https://media.retroachievements.org/Images/098694.png', 4.1),
  (161, 15356, 'LEGO Pirates of the Caribbean: The Video Game', 'Nintendo DS', 18, 203, 203, 203, 33, 0, 'Action-Adventure', 'TT Fusion', 'Disney Interactive Studios', '2011-05-13', 'Lego Pirates of the Caribbean: The Video Game is a 2011 Lego-themed action-adventure video game, based on the Pirates of the Caribbean film series, developed by Traveller''s Tales and published by Disney Interactive Studios for Xbox 360, PlayStation 3, PlayStation Portable, Wii, Nintendo DS, Nintendo 3DS, Microsoft Windows, and Mac OS X. The game was released to coincide with the release of Pirates of the Caribbean: On Stranger Tides, and retells the plot of the first four films in the Pirates Of The Caribbean series.', 'https://media.retroachievements.org/Images/043024.png', 'https://media.retroachievements.org/Images/043020.png', 'https://media.retroachievements.org/Images/043431.png', 'https://media.retroachievements.org/Images/043421.png', 4.1),
  (162, 17232, 'Another Code: Two Memories', 'Nintendo DS', 18, 202, 202, 202, 22, 0, 'Point-and-Click Adventure', 'Cing', 'Nintendo', '2005-02-24', 'Another Code: Two Memories, known as Trace Memory in North America, is a 2005 point-and-click adventure game developed by Cing and published by Nintendo for the Nintendo DS. The game was first released in Japan on February 24, 2005, with releases in Europe, Australia, and North America, following later the same year.', 'https://media.retroachievements.org/Images/057826.png', 'https://media.retroachievements.org/Images/057833.png', 'https://media.retroachievements.org/Images/057834.png', 'https://media.retroachievements.org/Images/057835.png', 4.1),
  (163, 16717, 'Cooking Mama 3: Shop & Chop', 'Nintendo DS', 18, 198, 198, 198, 39, 0, 'Cooking Simulation', 'Cooking Mama Limited', 'Majesco Entertainment', '2009-10-20', 'Cooking Mama 3: Shop & Chop released as Cooking Mama 3 in Japan, Europe and Australia, is the sequel to the Nintendo DS video game Cooking Mama 2: Dinner with Friends and the third installment in the Cooking Mama series. Developed by 505 Games, Majesco Entertainment, and Taito, Shop & Chop features five different game modes, including two new ones, over 80 different recipes, 200 unique mini-games, four-player multiplayer, and the classic gameplay.', 'https://media.retroachievements.org/Images/086682.png', 'https://media.retroachievements.org/Images/053229.png', 'https://media.retroachievements.org/Images/086700.png', 'https://media.retroachievements.org/Images/086701.png', 4.1),
  (164, 15352, 'LEGO Indiana Jones: The Original Adventures', 'Nintendo DS', 18, 197, 197, 197, 30, 0, 'Action-Adventure', 'TT Fusion', 'LucasArts | Lucasfilm', '2008-06-17', 'Lego Indiana Jones: The Original Adventures is a 2008 Lego-themed action-adventure video game developed by Traveller''s Tales and published by LucasArts. Based on the Indiana Jones franchise and the eponymous Lego Indiana Jones toy line, it follows the events of the first three Indiana Jones films: Raiders of the Lost Ark (1981), Temple of Doom (1984), and the Last Crusade (1989). The game includes local co-op mode gameplay, as well as puzzle and platformer aspects, and 84 playable characters with a variety of special abilities. As the players go through the stages, they collect the currency of Lego games known as Studs, avoid traps, assemble Lego constructions, and engage in combat. Climbing, swinging, and throwing objects as weapons were new inclusions not seen in previous Lego video games by Traveller''s Tales.', 'https://media.retroachievements.org/Images/044390.png', 'https://media.retroachievements.org/Images/044227.png', 'https://media.retroachievements.org/Images/044228.png', 'https://media.retroachievements.org/Images/044229.png', 4.1),
  (165, 3140, 'Izuna 2: The Unemployed Ninja Returns', 'Nintendo DS', 18, 195, 195, 195, 40, 0, 'Roguelike', 'Success, Ninja Studio', 'Atlus', '2007-11-29', 'Izuna 2: The Unemployed Ninja Returns, released in Japan as Gōma Reifu Den Izuna Ni , is a dungeon crawler video game developed by Ninja Studio and published in Japan by Success and in North America by Atlus for the Nintendo DS handheld game console. It is the sequel to Izuna: Legend of the Unemployed Ninja and was released in Japan on November 29, 2007 and in North America on July 22, 2008.', 'https://media.retroachievements.org/Images/063014.png', 'https://media.retroachievements.org/Images/062514.png', 'https://media.retroachievements.org/Images/062633.png', 'https://media.retroachievements.org/Images/062632.png', 4.1),
  (166, 1741, 'Space Invaders Extreme 2', 'Nintendo DS', 18, 193, 193, 193, 97, 0, 'Shoot ''em Up', 'Taito', 'Square Enix', '2009-03-26', 'Space Invaders Extreme 2  is the sequel to Space Invaders Extreme. Space Invaders Extreme 2 features new content compared to its predecessor. A cut-down version of the game called Space Invaders Extreme Z has been made available on DSiWare for 500 Points.', 'https://media.retroachievements.org/Images/104937.png', 'https://media.retroachievements.org/Images/029075.png', 'https://media.retroachievements.org/Images/104913.png', 'https://media.retroachievements.org/Images/104915.png', 4.1),
  (167, 1204, 'Chibi-Robo! Park Patrol', 'Nintendo DS', 18, 192, 192, 192, 48, 0, 'Park Ranger Simulator', NULL, 'Nintendo', '2007-07-05', 'Chibi-Robo! Park Patrol is a platform-adventure video game for the Nintendo DS. Developed by Skip Ltd. and published by Nintendo, it is the second installment in the Chibi-Robo series and the sequel to the original Chibi-Robo! for the GameCube. It was released in July 2007 in Japan, followed by a North American release the following October exclusive to Walmart stores.', 'https://media.retroachievements.org/Images/107401.png', 'https://media.retroachievements.org/Images/078931.png', 'https://media.retroachievements.org/Images/042473.png', 'https://media.retroachievements.org/Images/042472.png', 4),
  (168, 9489, 'The Dark Spire', 'Nintendo DS', 18, 192, 192, 192, 74, 0, NULL, 'Success', 'Atlus', '2009-04-14', 'The Dark Spire, known as Genmu no Tō to Tsurugi no Okite in Japan, is a role-playing game developed by Success for the Nintendo DS. It was released on May 22, 2008 in Japan and April 14, 2009 in North America which was published by Atlus.', 'https://media.retroachievements.org/Images/118824.png', 'https://media.retroachievements.org/Images/057394.png', 'https://media.retroachievements.org/Images/028644.png', 'https://media.retroachievements.org/Images/057392.png', 4),
  (169, 16716, 'Cooking Mama 2: Dinner with Friends', 'Nintendo DS', 18, 190, 190, 190, 25, 0, 'Cooking Simulation', 'Cooking Mama Limited', NULL, '2007-11-13', 'Cooking Mama 2: Dinner with Friends is the sequel to the Nintendo DS video game Cooking Mama and its Wii spin off, Cooking Mama: Cook Off. The game has twice as many minigames as the original, new recipes, and a new multiplayer "Cook Off" mode. The game includes voice clips similar to the ones used in Cooking Mama: Cook Off.', 'https://media.retroachievements.org/Images/071848.png', 'https://media.retroachievements.org/Images/051582.png', 'https://media.retroachievements.org/Images/049649.png', 'https://media.retroachievements.org/Images/049648.png', 4),
  (170, 14789, 'Tingle''s Balloon Fight DS', 'Nintendo DS', 18, 190, 190, 190, 26, 0, '2D Platforming', 'Vanpool', 'Nintendo', '2007-04-12', 'Balloon Fight is a 1984 action video game developed by Nintendo and HAL Laboratory and published by Nintendo for the Nintendo Entertainment System. It was originally released for arcades as VS. Balloon Fight, with the console version releasing in Japan in 1985 and internationally in 1986.', 'https://media.retroachievements.org/Images/115558.png', 'https://media.retroachievements.org/Images/028970.png', 'https://media.retroachievements.org/Images/028732.png', 'https://media.retroachievements.org/Images/061563.png', 4),
  (171, 25801, '~Homebrew~ Fishing the Deep', 'Nintendo DS', 18, 187, 187, 187, 6, 0, 'Sports - Fishing', 'SurrealCubeMedia', 'SurrealCubeMedia', '2021-04-27', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/082612.png', 'https://media.retroachievements.org/Images/082611.png', 'https://media.retroachievements.org/Images/082609.png', 'https://media.retroachievements.org/Images/082610.png', 4),
  (172, 18612, 'Thomas & Friends: Hero of the Rails', 'Nintendo DS', 18, 183, 183, 183, 20, 0, 'Educational, Racing', 'Fuse Games | Silverball Studios', 'Barnstorm Games', '2010-08-20', 'Thomas & Friends: Hero of the Rails is a 2009 British animated adventure film and the third feature-length special based on the British television series Thomas & Friends. The film was produced and distributed by HIT Entertainment with animation production by Canadian-based Nitrogen Studios. The movie centres on Thomas finding a long-lost engine from Japan named Hiro and attempting to repair him, opposed by malicious private engine Spencer.', 'https://media.retroachievements.org/Images/121437.png', 'https://media.retroachievements.org/Images/053572.png', 'https://media.retroachievements.org/Images/053570.png', 'https://media.retroachievements.org/Images/053571.png', 4),
  (173, 15453, 'One Piece: Gigant Battle!', 'Nintendo DS', 18, 182, 182, 182, 67, 0, '2D Fighting', 'Ganbarion', 'Bandai Namco', '2011-07-01', 'The One Piece video games are based on Eiichiro Oda''s manga and anime series of the same name. Most games are published by Bandai Namco Entertainment, formerly Bandai and Banpresto. The games take place in the fictional world of One Piece, and the stories revolve around the adventures of Monkey D. Luffy and his Straw Hat Pirates, the franchise''s protagonists.', 'https://media.retroachievements.org/Images/068220.png', 'https://media.retroachievements.org/Images/057781.png', 'https://media.retroachievements.org/Images/057783.png', 'https://media.retroachievements.org/Images/057782.png', 4),
  (174, 30328, '~Prototype~ Nicktoons: Android Invasion', 'Nintendo DS', 18, 181, 181, 181, 8, 0, '2D Platforming, Educational', 'WayForward', NULL, '2007-01-01', ' The SpongeBob SquarePants video game series is a collection of video games and arcade games based on the Nickelodeon animated television series SpongeBob SquarePants and its film series with the same name. The television series'' massive rise in popularity during the 2000s led to a myriad of video games that span different genres. Several of these games are based on concepts from specific episodes, two of which are based on theatrical releases. Some of these titles had multiple different versions developed for a variety of home consoles and handheld consoles. Until 2013, the vast majority of titles were published by THQ. From 2013 to 2015, the license for most titles was handed to Activision. The license is currently held by THQ Nordic. Video games based on the series have often received mixed reviews from critics, yet many of these titles have performed well in sales.', 'https://media.retroachievements.org/Images/099895.png', 'https://media.retroachievements.org/Images/099894.png', 'https://media.retroachievements.org/Images/099900.png', 'https://media.retroachievements.org/Images/099901.png', 4),
  (175, 17066, 'Ben 10: Alien Force', 'Nintendo DS', 18, 176, 176, 176, 33, 0, 'Beat ''em Up', 'Vicious Cycle Software', 'D3 Publisher', '2008-10-28', 'Ben 10: Alien Force is an American animated television series created by team Man of Action, and produced by Cartoon Network Studios. It is the sequel to Ben 10 (2005–2008), set five years later and taking a darker turn than its predecessor.', 'https://media.retroachievements.org/Images/039586.png', 'https://media.retroachievements.org/Images/039510.png', 'https://media.retroachievements.org/Images/039513.png', 'https://media.retroachievements.org/Images/039512.png', 4),
  (176, 16299, 'Yu-Gi-Oh! World Championship 2008', 'Nintendo DS', 18, 176, 176, 176, 141, 0, 'Collectible Card Game', 'Konami', 'Konami', '2007-12-04', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/084155.png', 'https://media.retroachievements.org/Images/039366.png', 'https://media.retroachievements.org/Images/083464.png', 'https://media.retroachievements.org/Images/083466.png', 4),
  (177, 16240, 'The Urbz: Sims in the City', 'Nintendo DS', 18, 175, 175, 175, 89, 0, 'Life Simulation, Strategy', 'Griptonite Games, Maxis', 'Electronic Arts', '2004-11-17', 'The Urbz: Sims in the City is a 2004 life simulation video game developed by Maxis and published by Electronic Arts for the Game Boy Advance, GameCube, PlayStation 2, Xbox, and Nintendo DS. It is the third Sims game for consoles, and the second not to be released for Microsoft Windows, after a planned PC port and sequel were both cancelled due to mediocre sales. The next release for consoles and handhelds was the console port of The Sims 2.', 'https://media.retroachievements.org/Images/088902.png', 'https://media.retroachievements.org/Images/059984.png', 'https://media.retroachievements.org/Images/041852.png', 'https://media.retroachievements.org/Images/041853.png', 4),
  (178, 26532, 'Dora the Explorer: Dora Saves the Mermaids', 'Nintendo DS', 18, 173, 173, 173, 6, 0, 'Adventure, Educational', 'Black Lantern Studios', '2K Games', '2007-11-05', 'Multiple video games based on the 2000 Nick Jr. television show Dora the Explorer have been released. Most of these games have received a mixed critical reception. Unlike other video games, these were not released in Asia, due to the TV show having less interest in that continent than North America and Europe. A number of other video games were released exclusively for the Nick Jr. website, such as Dora''s 3D Driving Adventure, and Dora''s 3D Pyramid Adventure.', 'https://media.retroachievements.org/Images/121220.png', 'https://media.retroachievements.org/Images/087508.png', 'https://media.retroachievements.org/Images/113489.png', 'https://media.retroachievements.org/Images/113490.png', 4),
  (179, 17320, 'MySims', 'Nintendo DS', 18, 173, 173, 173, 63, 0, 'Life Simulation', 'TOSE', 'Electronic Arts', '2007-09-18', 'MySims is a video game developed by EA Redwood Shores and published by Electronic Arts as a spin-off to Maxis''s The Sims franchise for the Wii and Nintendo DS in September 2007, re-released for Microsoft Windows and mobile phones in 2008, and for BlackBerry in 2009. The game sold over 4 million units as of 2008.', 'https://media.retroachievements.org/Images/120893.png', 'https://media.retroachievements.org/Images/042824.png', 'https://media.retroachievements.org/Images/042822.png', 'https://media.retroachievements.org/Images/086706.png', 4),
  (180, 31371, 'Pass the Pigs: Let the Good Swines Roll!', 'Nintendo DS', 18, 172, 172, 172, 31, 0, 'Board Game', 'AWE Games', 'THQ', '2008-10-21', ' This is a list of video games that were published or distributed by THQ.', 'https://media.retroachievements.org/Images/107289.png', 'https://media.retroachievements.org/Images/103946.png', 'https://media.retroachievements.org/Images/103949.png', 'https://media.retroachievements.org/Images/103950.png', 4),
  (181, 20077, 'Puzzler World 2011', 'Nintendo DS', 18, 172, 172, 172, 82, 0, 'Puzzle', 'Ideas Pad', 'UFO Interactive', '2010-10-10', 'This is a list of physical video games for the Nintendo DS, DS Lite, and DSi handheld game consoles. It does not include games released on DSiWare or the iQue DS. The last game for the Nintendo DS, Big Hero 6: Battle in the Bay, was released on October 28, 2014.', 'https://media.retroachievements.org/Images/060150.png', 'https://media.retroachievements.org/Images/060146.png', 'https://media.retroachievements.org/Images/060145.png', 'https://media.retroachievements.org/Images/059924.png', 4),
  (182, 9701, 'Touch the Dead | Dead ''n'' Furious', 'Nintendo DS', 18, 172, 172, 172, 56, 0, 'Rail Shooter, Survival Horror', 'Dream On Studio', 'Eidos Interactive, Virgin Interactive', '2007-05-16', 'Touch the Dead is a rail shooter/survival horror game for the Nintendo DS developed by French company Dream On Studio. The game was originally published by Virgin Play in Europe as one of their first published games, and was later co-published by Eidos Interactive and V.2 Play in North America. The game''s North American box art was created by artist Arthur Suydam, famous for his work on the Marvel Zombies line of comics.', 'https://media.retroachievements.org/Images/070109.png', 'https://media.retroachievements.org/Images/077273.png', 'https://media.retroachievements.org/Images/102454.png', 'https://media.retroachievements.org/Images/102455.png', 4),
  (183, 16154, 'Digimon World Championship', 'Nintendo DS', 18, 170, 170, 170, 46, 0, 'Life Simulation, Real-Time Strategy', 'Epics', 'Bandai Namco', '2008-02-14', 'Digimon World Championship is a life simulation video game developed by Epics and published by Bandai Namco Games for the Nintendo DS, as part of the Digimon franchise. It was released in Japan in February 2008 and North America in August 2008. Despite its localized title in North America, the game is not part of the Digimon World sub-series of role-playing games.', 'https://media.retroachievements.org/Images/107265.png', 'https://media.retroachievements.org/Images/067729.png', 'https://media.retroachievements.org/Images/067730.png', 'https://media.retroachievements.org/Images/067731.png', 4),
  (184, 20263, 'Diner Dash: Flo on the Go', 'Nintendo DS', 18, 169, 169, 169, 92, 0, 'Job Simulation', 'PlayFirst', 'Zoo Digital Publishing | Zushi Games', '2009-10-27', 'Diner Dash: Flo on the Go is the third installment to the game series Diner Dash. It is published by PlayFirst and was released in October 2006.', 'https://media.retroachievements.org/Images/061085.png', 'https://media.retroachievements.org/Images/060595.png', 'https://media.retroachievements.org/Images/060975.png', 'https://media.retroachievements.org/Images/060974.png', 4),
  (185, 16755, 'Orcs and Elves', 'Nintendo DS', 18, 168, 168, 168, 66, 0, 'CRPG, Dungeon Crawl', 'Fountainhead Entertainment, id Software', 'Electronic Arts', '2007-11-13', 'Orcs & Elves is a 2006 role-playing video game for the mobile phone and Nintendo DS. It was developed by id Software and Fountainhead Entertainment and published by EA Mobile and licensed by Nintendo for the DS version. It was released for mobile phones in May 2006 before being ported to the Nintendo DS in November 2007. The game is based on Doom RPG''s engine and is id''s first original intellectual property since Quake. The DS port of the game included graphical enhancements, such as 3D environments and camera cutscenes, along with improved character sprites, two new levels and the use of the touchscreen feature.', 'https://media.retroachievements.org/Images/056285.png', 'https://media.retroachievements.org/Images/056286.png', 'https://media.retroachievements.org/Images/056284.png', 'https://media.retroachievements.org/Images/056485.png', 4),
  (186, 14974, '~Homebrew~ New Zelda', 'Nintendo DS', 18, 166, 166, 166, 8, 0, '2D Platforming', 'Lupi', 'Lupi', '2006-08-02', 'The Nintendo DS is a foldable handheld game console developed by Nintendo and released worldwide in 2004 and 2005. The "DS" in the name is an initialism for "Dual Screen", reflecting the system''s most distinctive feature: two LCD screens working in tandem, with the lower screen functioning as a touchscreen. Both screens are housed in a clamshell design similar to that of the Game Boy Advance SP and some models of the Game & Watch series. The DS was among the first portable consoles to support wireless connectivity for local multiplayer over short distances, as well as online play through the now-defunct Nintendo Wi-Fi Connection service. Its primary competitor during the seventh generation of video game consoles was Sony''s PlayStation Portable.', 'https://media.retroachievements.org/Images/111719.png', 'https://media.retroachievements.org/Images/035045.png', 'https://media.retroachievements.org/Images/035125.png', 'https://media.retroachievements.org/Images/035126.png', 4),
  (187, 16300, 'Yu-Gi-Oh! 5D''s World Championship 2011: Over the Nexus', 'Nintendo DS', 18, 164, 164, 164, 92, 0, 'Collectible Card Game, Racing', 'Konami', 'Konami', '2011-03-25', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/049794.png', 'https://media.retroachievements.org/Images/073263.png', 'https://media.retroachievements.org/Images/099870.png', 'https://media.retroachievements.org/Images/099871.png', 4),
  (188, 11637, 'Harvest Moon DS', 'Nintendo DS', 18, 163, 163, 163, 224, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2005-03-17', 'Harvest Moon DS, known in Japan as Bokujō Monogatari: Colobocle Station , is a farm simulation role-playing video game for the Nintendo DS, part of the Story of Seasons series. It was published and developed by Marvelous Interactive Inc., and released in Japan on March 17, 2005, and in North America on September 12, 2006. It is the first entry in the series without series creator Yasuhiro Wada heavily involved, though it borrows many assets from Harvest Moon: Friends of Mineral Town and Harvest Moon: A Wonderful Life, such as the graphical style from the former and setting of the latter.', 'https://media.retroachievements.org/Images/061248.png', 'https://media.retroachievements.org/Images/067505.png', 'https://media.retroachievements.org/Images/060946.png', 'https://media.retroachievements.org/Images/060947.png', 4),
  (189, 17155, 'eSMART', 'Nintendo DS', 18, 161, 161, 161, 16, 0, 'Job Simulation', NULL, 'McDonald''s', '2010-01-01', 'The Nintendo DS is a foldable handheld game console developed by Nintendo and released worldwide in 2004 and 2005. The "DS" in the name is an initialism for "Dual Screen", reflecting the system''s most distinctive feature: two LCD screens working in tandem, with the lower screen functioning as a touchscreen. Both screens are housed in a clamshell design similar to that of the Game Boy Advance SP and some models of the Game & Watch series. The DS was among the first portable consoles to support wireless connectivity for local multiplayer over short distances, as well as online play through the now-defunct Nintendo Wi-Fi Connection service. Its primary competitor during the seventh generation of video game consoles was Sony''s PlayStation Portable.', 'https://media.retroachievements.org/Images/048969.png', 'https://media.retroachievements.org/Images/046340.png', 'https://media.retroachievements.org/Images/040179.png', 'https://media.retroachievements.org/Images/040180.png', 4),
  (190, 15334, 'Mega Man Star Force: Leo', 'Nintendo DS', 18, 160, 160, 160, 64, 0, 'Action RPG', 'Capcom', 'Capcom', '2006-12-14', 'Mega Man Star Force: Leo, Mega Man Star Force: Dragon, and Mega Man Star Force: Pegasus, are 2006 action role-playing games developed and published by Capcom for the Nintendo DS handheld video game console; combined, they are the first game in the Mega Man Star Force series, a sub-series of the Mega Man franchise—and a follow-up to the Mega Man Battle Network series. It takes place in the years of 220X, in which technology has advanced to the point where the world is now connected through EM waves. The game follows Geo Stelar, an 11-year-old fifth-grader in Echo Ridge who merges with an FM-ian alien named Omega-Xis after mourning the supposed death of his father Kelvin Stelar.', 'https://media.retroachievements.org/Images/121809.png', 'https://media.retroachievements.org/Images/050334.png', 'https://media.retroachievements.org/Images/030379.png', 'https://media.retroachievements.org/Images/030380.png', 4),
  (191, 17674, 'Need for Speed: Carbon - Own the City', 'Nintendo DS', 18, 160, 160, 160, 40, 0, NULL, NULL, NULL, '2006-10-31', 'Need for Speed: Carbon – Own the City is a 2006 racing video game and the third portable installment in the Need for Speed series. Developed by Team Fusion and published by Electronic Arts, it was released on October 31, 2006, for the PlayStation Portable, Game Boy Advance, Nintendo DS and on May 25, 2009 as a pack-in title for the Zeebo. The game, a companion title to Need for Speed: Carbon, includes new or modified gameplay elements, a different setting and storyline, and a different selection of teammates. It is the final installment in the series to be released for Game Boy Advance.', 'https://media.retroachievements.org/Images/069477.png', 'https://media.retroachievements.org/Images/057794.png', 'https://media.retroachievements.org/Images/069476.png', 'https://media.retroachievements.org/Images/062525.png', 4),
  (192, 1983, 'Elf Bowling 1 & 2', 'Nintendo DS', 18, 159, 159, 159, 13, 0, 'Sports - Bowling', 'Black Lantern Studios', 'Ignition Entertainment', '2005-12-01', 'Elf Bowling is a bowling video game developed by NStorm and released in 1998 for Windows Computers. In the game  the player, as Santa Claus, attempts to knock down elves who are arranged like bowling pins. A later release of the game, by Ignition Entertainment, was released on the Nintendo handheld consoles Nintendo DS and Game Boy Advance, and received overwhelmingly negative reviews from critics. In Elf Bowling, the elves of Santa''s Workshop are on strike due to overwork from the huge demand for Christmas toys, so Santa Claus has decided to whip them into shape by using them as bowling pins.', 'https://media.retroachievements.org/Images/075759.png', 'https://media.retroachievements.org/Images/033053.png', 'https://media.retroachievements.org/Images/033050.png', 'https://media.retroachievements.org/Images/033051.png', 4),
  (193, 8705, 'Point Blank DS', 'Nintendo DS', 18, 159, 159, 159, 54, 0, 'Arcade, Minigames', 'TOSE', 'Bandai Namco', '2006-06-13', 'Point Blank DS is a 2006 lightgun shooter video game developed and published for the Nintendo DS by Namco Bandai Games. It is the fourth entry in the Point Blank series, comprising both new stages and ones taken from the first three games. Players use the touch screen to complete a number of different minigames that vary in terms of mechanics, such as protecting an on-screen character or shooting down a specific target.', 'https://media.retroachievements.org/Images/084348.png', 'https://media.retroachievements.org/Images/084347.png', 'https://media.retroachievements.org/Images/084350.png', 'https://media.retroachievements.org/Images/084351.png', 4),
  (194, 15521, 'Bleach: Dark Souls', 'Nintendo DS', 18, 158, 158, 158, 62, 0, '2D Fighting', 'Treasure', 'Sega', '2008-10-07', 'Bleach: Dark Souls, known in Japan as Bleach DS 2nd Kokui Hirameku Chinkonka is a fighting game developed by Treasure and published by Sega for the Nintendo DS. It is the second Bleach game released for the console. The game introduces new characters, and adds new moves for the older characters as well as introducing new game modes. Bleach: Dark Souls also includes Hollows of varying sizes, for players to fight. The number of Reifu cards in-game are also increased from the original, and more cards are displayed on the touch screen during battle. The Wi-Fi battle mode has been improved to make it easier to play online. The game''s theme song is "Resistance" by High and Mighty Color.', 'https://media.retroachievements.org/Images/049469.png', 'https://media.retroachievements.org/Images/049562.png', 'https://media.retroachievements.org/Images/049560.png', 'https://media.retroachievements.org/Images/049561.png', 4),
  (195, 14826, 'Bomberman', 'Nintendo DS', 18, 158, 158, 158, 54, 0, NULL, NULL, NULL, '2005-06-21', 'Bomberman  is a video game franchise created by Shinichi Nakamoto and Shigeki Fujiwara, originally developed by Hudson Soft and currently owned by Konami. The original game, also known as Bakudan Otoko, was released in Japan in July 1983 and has since spawned multiple sequels and spin-offs released on numerous platforms, as well as several anime and manga adaptations.', 'https://media.retroachievements.org/Images/120409.png', 'https://media.retroachievements.org/Images/041415.png', 'https://media.retroachievements.org/Images/028928.png', 'https://media.retroachievements.org/Images/074977.png', 4),
  (196, 12700, 'Rune Factory 3: A Fantasy Harvest Moon', 'Nintendo DS', 18, 158, 158, 158, 108, 0, 'Life Simulation', 'Neverland', 'Marvelous Entertainment, Natsume', '2009-10-22', 'Rune Factory 3: A Fantasy Harvest Moon is a 2009 simulation role-playing video game developed by Neverland for the Nintendo DS. It was published in Japan by Marvelous Entertainment, in North America by Natsume Inc. in 2010, and in Europe by Rising Star Games in 2011. It is the fourth game in the Rune Factory series.', 'https://media.retroachievements.org/Images/107476.png', 'https://media.retroachievements.org/Images/016530.png', 'https://media.retroachievements.org/Images/016540.png', 'https://media.retroachievements.org/Images/016534.png', 4),
  (197, 20897, 'TrackMania Turbo', 'Nintendo DS', 18, 158, 158, 158, 252, 0, 'Arcade Racing', 'Firebrand Games', 'Focus Home Interactive', '2010-09-24', 'TrackMania Turbo is a racing video game developed by Firebrand Games. The successor to TrackMania DS, it was released on September 24, 2010 in Europe by Focus Home Interactive, and on April 19, 2011 in the US by City Interactive. It was released at the same time as TrackMania: Build to Race for the Wii. It received generally favorable reviews from critics.', 'https://media.retroachievements.org/Images/113401.png', 'https://media.retroachievements.org/Images/106879.png', 'https://media.retroachievements.org/Images/106875.png', 'https://media.retroachievements.org/Images/106878.png', 4),
  (198, 4593, 'Dementium II', 'Nintendo DS', 18, 157, 157, 157, 40, 0, 'Survival Horror', 'Renegade Kid', 'SouthPeak Games', '2010-05-04', 'Dementium II is a 2010 survival horror first-person shooter video game developed by Renegade Kid and published by SouthPeak Games for the Nintendo DS. It is the sequel to 2007''s Dementium: The Ward. A remastered version of the game without involvement from Renegade Kid was released for Microsoft Windows and Mac OS X on December 17, 2013 to negative reviews.', 'https://media.retroachievements.org/Images/077965.png', 'https://media.retroachievements.org/Images/042329.png', 'https://media.retroachievements.org/Images/053283.png', 'https://media.retroachievements.org/Images/053284.png', 4),
  (199, 11734, 'Contact', 'Nintendo DS', 18, 156, 156, 156, 156, 0, 'Action RPG', 'Grasshopper Manufacture', 'Atlus', '2006-10-17', 'Contact is a role-playing video game developed by Grasshopper Manufacture for the Nintendo DS handheld game console. It was published by Marvelous Entertainment in Japan on March 30, 2006, by Atlus USA in North America on October 18, and by Rising Star Games in Australia, Asia and Europe on January 25, 2007 and February 2, respectively.', 'https://media.retroachievements.org/Images/070782.png', 'https://media.retroachievements.org/Images/028642.png', 'https://media.retroachievements.org/Images/028643.png', 'https://media.retroachievements.org/Images/028641.png', 4),
  (200, 15380, 'Postman Pat', 'Nintendo DS', 18, 156, 156, 156, 24, 0, 'Minigames', 'The Code Monkeys', 'Blast! Entertainment', '2008-03-14', 'Postman Pat is a British stop motion animated children''s television series first produced by Woodland Animations. The series follows the adventures of Pat Clifton, a postman who works for the Royal Mail postal service in the fictional village of Greendale.', 'https://media.retroachievements.org/Images/085718.png', 'https://media.retroachievements.org/Images/085547.png', 'https://media.retroachievements.org/Images/085964.png', 'https://media.retroachievements.org/Images/085963.png', 4);
